const PROC_CATS = {"caisse": {"label": "Caisse & Période", "icon": "🏦", "theme": "procedures"}, "tarification": {"label": "Tarification", "icon": "📋", "theme": "procedures"}, "ccp_pmi": {"label": "CCP / PMI / TUH", "icon": "💻", "theme": "procedures"}, "delivrance": {"label": "Délivrance & FLAGS", "icon": "📦", "theme": "procedures"}, "commandes": {"label": "Commandes & Retours", "icon": "🛒", "theme": "procedures"}, "listes": {"label": "Listes & Listings", "icon": "📃", "theme": "procedures"}, "galien": {"label": "Galien", "icon": "🔵", "theme": "procedures"}, "b2b_facturation": {"label": "B2B & Facturation", "icon": "🏥", "theme": "procedures"}, "stock": {"label": "Stock & Péremptions", "icon": "📦", "theme": "procedures"}, "informatique": {"label": "Informatique", "icon": "🖥️", "theme": "procedures"}, "stupefiants": {"label": "Stupéfiants & Narcoreg", "icon": "🔐", "theme": "procedures"}, "retours": {"label": "Retours & Transferts", "icon": "🔄", "theme": "procedures"}};
const PROC_QDB = [{"t": "Procédure", "sub": "caisse", "d": "essentiel", "q": "Lors de la clôture de caisse en fin de période, où faut-il annexer la feuille des retraits/dépôts ?", "a": ["Dans le bac gris avec les ordonnances", "Dans la farde rouge et le sac bleu", "Dans le classeur de facturation EPC", "Sur le bureau du pharmacien responsable"], "r": 1, "e": "Selon FP-CAI-001, après impression de la liste des retraits/dépôts, la feuille doit être annexée avec les feuilles de caisse dans la farde rouge et le sac bleu. Ce geste est la dernière étape de la procédure de clôture.|||💡 Point pratique : Farde rouge + sac bleu = destination caisse. Bac gris = tarification.", "fiche": "FP-CAI-001"}, {"t": "Procédure", "sub": "caisse", "d": "essentiel", "q": "Quel profil est obligatoire pour réaliser la clôture de caisse fin de période dans CCP ?", "a": ["Membre du personnel (délivrance)", "Assistant en pharmacie", "Pharmacien (badge obligatoire)", "Chef de rayon"], "r": 2, "e": "FP-CAI-001 précise que la clôture de caisse requiert le profil Pharmacien avec badge obligatoire. La première étape est explicitement 'se badger en pharmacien' avant toute action.|||💡 Point pratique : Badge pharmacien = condition sine qua non pour la caisse. Sans badge correct, la procédure ne peut pas être lancée.", "fiche": "FP-CAI-001"}, {"t": "Procédure", "sub": "caisse", "d": "essentiel", "q": "En fin de période, quelle est la fréquence des clôtures chez Familia ?", "a": ["1 clôture par mois le dernier jour", "4 périodes : 1-7 / 8-14 / 15-21 / 22-fin de mois", "2 clôtures par mois (1-15 et 16-fin)", "Clôture chaque vendredi"], "r": 1, "e": "FP-SYN-001 indique clairement que Familia travaille avec 4 périodes par mois : 1-7, 8-14, 15-21, et 22-fin de mois. Cette structure de période s'applique à la caisse, la tarification et la facturation.|||💡 Point pratique : Mémoriser les 4 périodes — elles rythment toutes les clôtures administratives.", "fiche": "FP-SYN-001"}, {"t": "Procédure", "sub": "tarification", "d": "essentiel", "q": "Lors de la clôture période Ordonnance dans CCP, quel onglet faut-il imprimer après avoir appliqué les filtres ?", "a": ["Facturation institution", "Suspens/Litiges par famille", "Prescription par org. assureur excepté INAMI", "Ordonnances en attente"], "r": 2, "e": "FP-TAR-001 : après avoir décoché tout sauf 'Afficher les données de tarif excepté INAMI' et cliqué Appliquer, il faut cliquer sur l'onglet 'Prescription par org. assureur excepté INAMI' puis imprimer. Cette feuille est ensuite annexée dans le bac gris.|||💡 Point pratique : Bac gris = destination de toutes les impressions de tarification période.", "fiche": "FP-TAR-001"}, {"t": "Procédure", "sub": "tarification", "d": "essentiel", "q": "Quand faut-il impérativement imprimer le listing des ordonnances en attente (FP-TAR-002) ?", "a": ["Après la clôture de tarification", "Avant la clôture de tarification", "Le lendemain de la clôture de période", "En début de mois uniquement"], "r": 1, "e": "FP-TAR-002 porte une alerte explicite : 'À faire AVANT de clôturer la tarification'. L'objectif est de gérer les CBU manquants et les réservés payés pour libérer les ordonnances avant la tarification. Faire cela après serait trop tard.|||💡 Point pratique : Le listing ordonnances en attente est un pré-requis, pas une option. Il permet d'éviter des ordonnances bloquées.", "fiche": "FP-TAR-002"}, {"t": "Procédure", "sub": "tarification", "d": "essentiel", "q": "Comment envoyer le fichier électronique de tarification à EPC en fin de mois ?", "a": ["Par mail à retours@pharmacie-familia.be", "Via le bouton 'Terre EPC' dans CCP Tarification", "Via Galien → Suivi → Export EPC", "Par clé USB vers le serveur de production"], "r": 1, "e": "FP-TAR-003 et FP-SYN-001 précisent tous deux : l'envoi électronique se fait en cliquant sur la 'Terre EPC' dans Exploitation → Tarification. Un message de confirmation apparaît, il faut cliquer OK puis quitter.|||💡 Point pratique : 'Terre EPC' = envoi électronique. Distinct de l'impression papier qui va dans le bac gris.", "fiche": "FP-TAR-003"}, {"t": "Procédure", "sub": "tarification", "d": "essentiel", "q": "La tarification fin de mois doit se faire à quel moment précis ?", "a": ["Avant la dernière clôture de période", "En même temps que la clôture de la dernière période", "Après la dernière clôture de période du mois", "Le 1er du mois suivant"], "r": 2, "e": "FP-TAR-003 porte une alerte claire : 'À faire APRÈS la dernière clôture de période du mois.' L'ordre est donc : dernière clôture de période → puis tarification fin de mois avec envoi à EPC.|||💡 Point pratique : L'ordre est crucial — tarification mensuelle toujours en dernier, jamais avant la clôture de la dernière période.", "fiche": "FP-TAR-003"}, {"t": "Procédure", "sub": "ccp_pmi", "d": "approfondi", "q": "Avant d'annuler une production dans CCP, que faut-il vérifier en priorité ?", "a": ["Que la caisse est clôturée pour la période", "L'absence de productions non modifiables — sinon contacter informatique@pharmacie-familia.be", "Que le patient est bien référencé dans Galien", "Que le Therapylink a été passé pour la semaine"], "r": 1, "e": "FP-CCP-001 indique une alerte en introduction : avant d'annuler, vérifier l'absence de productions non modifiables. Si présentes, envoyer un mail à informatique@pharmacie-familia.be avant de continuer. Annuler sans cette vérification peut causer des problèmes irréversibles.|||💡 Point pratique : Productions non modifiables = stopper et mailer l'informatique. Ne jamais forcer l'annulation.", "fiche": "FP-CCP-001"}, {"t": "Procédure", "sub": "ccp_pmi", "d": "approfondi", "q": "Quel est le symptôme visible d'un problème d'assurabilité bloquant lors de la clôture de bloc CCP ?", "a": ["Un message d'erreur rouge dans CCP avec code EPC", "La gélule bleu/blanche est grisée — impossible de générer les schémas", "Le fichier Therapylink ne se charge pas dans Newsoft", "MyCareNet affiche un timeout de connexion"], "r": 1, "e": "FP-CCP-002 décrit exactement ce symptôme : 'la gélule bleu/blanche est grisée — impossible de générer les schémas.' C'est le signe d'une assurabilité MyCareNet bloquante sur un ou plusieurs patients.|||💡 Point pratique : Gélule grisée = problème MyCareNet. Identifier les patients bloquants et simuler une ordonnance pour débloquer via MemberData.", "fiche": "FP-CCP-002"}, {"t": "Procédure", "sub": "ccp_pmi", "d": "approfondi", "q": "Lors de la clôture des blocs (FP-CCP-003), que fait CCP automatiquement lors de l'étape FLAG 2 ?", "a": ["Il envoie un mail aux institutions concernées", "Il flag 2 automatiquement les comprimés restants pour les DCD et les attestations périmant dans le mois", "Il génère une liste de périmés à retirer du stock", "Il bloque les nouvelles délivrances pour les patients concernés"], "r": 1, "e": "FP-CCP-003 précise : 'CCP flag 2 automatiquement les comprimés restants pour les patients DCD et les attestations périmant dans le mois.' Ce comportement automatique évite un travail manuel de vérification.|||💡 Point pratique : Le FLAG 2 automatique de CCP est un filet de sécurité — mais cela ne dispense pas de vérifier visuellement la liste.", "fiche": "FP-CCP-003"}, {"t": "Procédure", "sub": "ccp_pmi", "d": "approfondi", "q": "Dans le flux Therapylink PMI, dans quel logiciel se déroule la phase de comparaison des schémas (traitements initiés, modifiés, arrêtés) ?", "a": ["Newsoft", "CCP (TUH)", "Galien", "Therapylib"], "r": 2, "e": "FP-PMI-003 décrit un flux en 3 logiciels : Newsoft (production), Galien (comparaison des schémas), CCP (TUH pour clôture des blocs). La comparaison — traitements initiés, modifiés, arrêtés — se fait dans Galien.|||💡 Point pratique : Flux PMI = Newsoft → Galien → CCP. Chaque logiciel a son rôle distinct.", "fiche": "FP-PMI-003"}, {"t": "Procédure", "sub": "ccp_pmi", "d": "approfondi", "q": "Si une modification est nécessaire après comparaison dans Galien lors du passage Therapylink, que faut-il faire ?", "a": ["Modifier directement dans Galien et valider", "Annuler la production dans Newsoft et passer un nouveau Therapylink", "Contacter le médecin prescripteur pour confirmation", "Mettre un FLAG 2 dans CCP et laisser la clôture se faire"], "r": 1, "e": "FP-PMI-003 indique clairement dans une alerte : 'Si modification nécessaire : annuler la production dans Newsoft et passer un nouveau Therapylink.' On ne modifie jamais directement dans Galien.|||💡 Point pratique : Annulation Newsoft + nouveau Therapylink = seule voie de correction. Modifier directement = erreur de procédure.", "fiche": "FP-PMI-003"}, {"t": "Procédure", "sub": "delivrance", "d": "essentiel", "q": "Pour quelle classe de médicaments faut-il systématiquement poser un FLAG 1 en délivrance ?", "a": ["Stupéfiants et préparations magistrales", "Antibiotiques (J01), antimycosiques (J02) et traitements chroniques petite boîte (initiation)", "Toutes les spécialités très chères remboursées", "Médicaments sous surveillance particulière CBIP"], "r": 1, "e": "FP-DEL-001 définit 3 catégories FLAG 1 : antibiotiques (J01), antimycosiques (J02), et traitement chronique petite boîte (initiation). Le FLAG 1 se pose en cliquant 'Info' sur la ligne du médicament puis en sélectionnant FLAG 1.|||💡 Point pratique : J01 + J02 + petite boîte initiation = FLAG 1 automatique. Les stupéfiants et grandes boîtes relèvent du FLAG 2.", "fiche": "FP-DEL-001"}, {"t": "Procédure", "sub": "delivrance", "d": "approfondi", "q": "Pour une délivrance hors PMI d'un produit PMI avec ordonnance, si le produit est déjà en PMI et délivré en plus, quel flag apposer ?", "a": ["FLAG 1", "FLAG 2", "Pas de flag — délivrance normale", "FLAG 3 (délivrance exceptionnelle)"], "r": 1, "e": "FP-PMI-001 précise : si le produit est déjà en PMI et délivré en plus → prévenir l'institution + FLAG 2. Le FLAG 2 s'applique aux délivrances exceptionnelles, aux grandes boîtes, et aux situations de double délivrance PMI.|||💡 Point pratique : Double délivrance PMI = FLAG 2 + prévenir l'institution. Ne jamais délivrer en double sans tracer.", "fiche": "FP-PMI-001"}, {"t": "Procédure", "sub": "delivrance", "d": "approfondi", "q": "Quelles sont les 2 conditions pour réaliser un BUM asthme au comptoir (FP-CONS-001) ?", "a": ["Ordonnance de renouvellement + patient adulte", "Première délivrance (12 mois) + asthme, OU traitement chronique insuffisamment contrôlé (ACT < 20) + pas de BUM depuis 12 mois + asthme", "Score ACT < 15 + patient sous corticoïde oral", "Demande du patient + accord du médecin prescripteur"], "r": 1, "e": "FP-CONS-001 liste deux conditions alternatives : soit c'est la première délivrance depuis 12 mois avec asthme, soit le traitement est insuffisamment contrôlé (score ACT < 20) sans BUM depuis 12 mois avec asthme. L'une des deux suffit.|||💡 Point pratique : Retenir ACT < 20 comme seuil de déclenchement. Après le BUM, noter 'BUM-asthme entretien 1 + date' dans la fiche patient.", "fiche": "FP-CONS-001"}, {"t": "Procédure", "sub": "delivrance", "d": "approfondi", "q": "Lors du 2e conditionnement de corticoïde inhalé après un BUM asthme, quel CNK faut-il faire ?", "a": ["5520390", "4312799", "3632940", "4875662"], "r": 0, "e": "FP-CONS-001 indique explicitement : lors du 2e conditionnement corticoïde, faire le CNK 5520390. Ce CNK déclenche le 2e entretien BUM dans CCP.|||💡 Point pratique : CNK 5520390 = entretien BUM n°2. À mémoriser ou coller sur le poste de délivrance.", "fiche": "FP-CONS-001"}, {"t": "Procédure", "sub": "commandes", "d": "essentiel", "q": "Quelle est l'heure limite pour valider les commandes journalières via la fusion de commande dans CCP ?", "a": ["Avant 16h00", "Avant 17h55", "Avant 18h30", "Avant 19h00"], "r": 1, "e": "FP-CMD-001 indique clairement : heure limite avant 17h55. La procédure inclut la sélection de 3 types de commandes dans la fusion : réservations EPC, manquants EPC, et commandes normales jusqu'à 17h55.|||💡 Point pratique : 17h55 = deadline commande. Passé cette heure, la commande EPC ne sera pas intégrée.", "fiche": "FP-CMD-001"}, {"t": "Procédure", "sub": "commandes", "d": "essentiel", "q": "Quels éléments faut-il sélectionner dans la Fusion de commande journalière ?", "a": ["Commandes manuelles + réservations PMI uniquement", "Commande EPC réservations + Commandes EPC manquants + Commandes normales jusqu'à 17h55", "Commandes normales + retours fournisseurs", "Commandes EPC + commandes Galien fusionnées"], "r": 1, "e": "FP-CMD-001 liste les 3 éléments à sélectionner dans la Fusion de commande : 'Commande EPC réservations', 'Commandes EPC manquants' et 'Commandes normales jusqu'à 17h55'. Les 3 doivent être cochés.|||💡 Point pratique : Vérifier que les 3 cases sont cochées avant de valider — une case manquante = des articles non commandés.", "fiche": "FP-CMD-001"}, {"t": "Procédure", "sub": "commandes", "d": "essentiel", "q": "Quand faut-il obligatoirement traiter les attentes de crédits (FP-CMD-002) ?", "a": ["1 fois par semaine en fin de période", "Chaque jour, après la commande ou après le RMR", "Uniquement après réception d'un bon de crédit physique", "En fin de mois lors de la tarification"], "r": 1, "e": "FP-CMD-002 porte une alerte explicite : 'À faire OBLIGATOIREMENT chaque jour après la commande ou le RMR.' La procédure commence par quitter entièrement CCP, puis le relancer en se rebadgeant.|||💡 Point pratique : Attentes de crédits = tâche quotidienne sans exception. Non fait = crédits non clôturés qui s'accumulent.", "fiche": "FP-CMD-002"}, {"t": "Procédure", "sub": "commandes", "d": "essentiel", "q": "Pour un RMR / transfert inter-officine, combien d'exemplaires du bon de renvoi faut-il imprimer ?", "a": ["1 exemplaire (pour le dossier officine)", "2 exemplaires (1 pour l'officine + 1 à agrafer au sac)", "3 exemplaires (officine, grossiste, retours)", "Pas d'impression — envoi électronique uniquement"], "r": 1, "e": "FP-CMD-003 indique : 'Cliquer sur Renvoyer en 2 exemplaires (1 pour l'officine + 1 à agrafer au sac).' Les 2 exemplaires ont des destinations distinctes et doivent être imprimés simultanément.|||💡 Point pratique : 2 exemplaires = règle systématique RMR. Un seul exemplaire = procédure incomplète.", "fiche": "FP-CMD-003"}, {"t": "Procédure", "sub": "commandes", "d": "approfondi", "q": "Dans CCP, si la question 'Voulez-vous ajouter la quantité supplémentaire ?' apparaît en fin de commande EPC, que faut-il répondre ?", "a": ["OUI — pour intégrer la quantité supplémentaire au stock", "NON — et vérifier la note d'envoi", "Annuler et relancer la commande", "Contacter EPC avant de répondre"], "r": 1, "e": "FP-CMD-004 alerte : 'Si CCP demande Voulez-vous ajouter la quantité supplémentaire ? → répondre NON et vérifier la note d'envoi.' Si l'article est absent de la note d'envoi, il doit retourner au dépôt via sac rouge avec document d'identification.|||💡 Point pratique : Toujours NON à cette question + vérification note d'envoi. Répondre OUI sans vérifier = stock faux.", "fiche": "FP-CMD-004"}, {"t": "Procédure", "sub": "listes", "d": "essentiel", "q": "Pour imprimer un listing d'attestations par patient dans CCP, où se trouve cette fonction ?", "a": ["Exploitation → Facturation → Attestations", "Listes → Acteurs et intervenants → Liste des attestations par patients", "TUH → Listes → Attestations patients", "Galien → Signalétique → Attestations"], "r": 1, "e": "FP-LST-001 : Listes → Acteurs et intervenants → double-cliquer sur 'Liste des attestations par patients' → choisir l'intervalle de date et/ou patient/institution → Appliquer puis Imprimer.|||💡 Point pratique : Le chemin complet compte — 'Acteurs et intervenants' est une sous-section de Listes peu intuitive.", "fiche": "FP-LST-001"}, {"t": "Procédure", "sub": "listes", "d": "essentiel", "q": "Pour obtenir le listing des réservés payés d'une institution, quelle case faut-il cocher dans CCP Tarification ?", "a": ["Prescription exceptée INAMI", "Ordonnances en attente", "Réservés payés uniquement", "Facturation inter-institution"], "r": 2, "e": "FP-LST-002 : après s'être badgé en pharmacien, aller dans Exploitation → Tarification, sélectionner l'intervalle + l'institution, puis cocher uniquement 'Réservés payés' → Appliquer puis Imprimer.|||💡 Point pratique : Cocher UNIQUEMENT réservés payés — les autres filtres doivent être décochés pour ne pas polluer le listing.", "fiche": "FP-LST-002"}, {"t": "Procédure", "sub": "listes", "d": "essentiel", "q": "Quel profil est requis pour sortir les litiges/suspens dans CCP (FP-LST-004) ?", "a": ["Délivrance", "Membre du personnel", "Pharmacien (badge obligatoire)", "Chef de rayon ou responsable de site"], "r": 2, "e": "FP-LST-004 précise que la première étape est 'Passer le badge PHARMACIEN à l'ouverture du programme.' Ce profil est obligatoire pour accéder à la section Suspens/Litiges dans CCP.|||💡 Point pratique : Suspens/Litiges = pharmacien requis. Sans le bon badge dès l'ouverture, la fonction n'est pas accessible.", "fiche": "FP-LST-004"}, {"t": "Procédure", "sub": "galien", "d": "approfondi", "q": "Lors de l'annulation d'une production non modifiable dans Galien (B2B), quelle erreur critique faut-il absolument éviter ?", "a": ["Lancer l'annulation sans badge pharmacien", "Supprimer le fichier regroupant TOUS les patients — il sera définitivement perdu", "Fermer Galien avant de cliquer OK", "Annuler depuis CCP plutôt que depuis Galien"], "r": 1, "e": "FP-GAL-001 porte une alerte en rouge : 'Ne pas supprimer le fichier regroupant TOUS les patients — il sera définitivement perdu !' Il faut prendre uniquement le fichier du jour avec les données concernées et cliquer sur Annuler au niveau du fichier correspondant.|||💡 Point pratique : Dans Galien B2B, annuler ≠ supprimer. Cibler le bon fichier (du jour) et jamais le fichier global.", "fiche": "FP-GAL-001"}, {"t": "Procédure", "sub": "galien", "d": "approfondi", "q": "Pour consulter les ventes d'un article dans les autres officines Familia via Galien, quel chemin suivre ?", "a": ["B2B → Production → Statistiques ventes", "Signalétique → Article → encoder le CNK → Consultation statistique → Vente officine", "Exploitation → Tarification → Ventes inter-officines", "TUH → Listes → Statistiques articles"], "r": 1, "e": "FP-GAL-002 : Galien → Signalétique → Article → encoder le CNK → Recherche → cliquer sur la ligne de la spécialité → Consultation statistique → Vente officine. Les ventes des autres officines s'affichent.|||💡 Point pratique : Utile pour vérifier si un article se vend mieux dans une autre officine avant de le mettre en non-commandable.", "fiche": "FP-GAL-002"}, {"t": "Procédure", "sub": "informatique", "d": "essentiel", "q": "Pour débloquer l'imprimante ticket après un encodage bloquant, quelle combinaison clavier permet de tout sélectionner dans la file d'attente ?", "a": ["CTRL + A", "ALT + A", "CTRL + DEL", "SHIFT + A"], "r": 1, "e": "FP-IT-001 : après avoir cliqué 1 fois sur le premier document en attente, faire ALT + A pour tout sélectionner, puis DELETE et cliquer Oui. La file d'attente doit être vide avant de rallumer l'imprimante.|||💡 Point pratique : ALT + A dans la file d'impression = sélectionner tout. Vérifier que la liste est bien vide avant de relancer l'imprimante.", "fiche": "FP-IT-001"}, {"t": "Procédure", "sub": "informatique", "d": "essentiel", "q": "Quelle application faut-il utiliser pour la configuration MFA chez Familia, et quel en est l'éditeur officiel ?", "a": ["Microsoft Authenticator (Microsoft Corporation)", "Google Authenticator (Google LLC) — aucune autre application ne fonctionne", "Authy (Twilio) — recommandée par EPC", "FamiliaAuth — application interne Familia"], "r": 1, "e": "FP-IT-002 est très explicite : 'Utiliser exclusivement l'application Google Authenticator du fournisseur Google LLC. Aucune autre application ne fonctionnera.' Le QR code se scanne depuis https://sspr-familia.groupe-epc.be/.|||💡 Point pratique : En cas de nouveau téléphone ou perte de téléphone, refaire la procédure complète depuis sspr-familia.groupe-epc.be.", "fiche": "FP-IT-002"}, {"t": "Procédure", "sub": "stock", "d": "essentiel", "q": "Quel est le délai standard de retrait des articles approchant leur date de péremption chez Familia ?", "a": ["6 mois avant la date de péremption", "4 mois avant (sauf frigos et alimentaires : 1 mois avant)", "3 mois avant pour tous les articles", "2 mois avant avec accord du service achat"], "r": 1, "e": "FP-STK-001 définit la règle : retrait 4 mois avant la date de péremption pour tous les articles, avec une exception pour les articles frigos et certains alimentaires : 1 mois avant. La procédure est réalisée 1× par mois au milieu du mois.|||💡 Point pratique : 4 mois = règle générale. Frigos et alimentaires = 1 mois. Articles retirés → zone TRP puis service des Retours.", "fiche": "FP-STK-001"}, {"t": "Procédure", "sub": "stock", "d": "approfondi", "q": "Si un article en duo a un seul exemplaire périmé, que faire selon FP-STK-001 ?", "a": ["Retirer le duo complet et envoyer les deux en TRP", "Dépareiller si possible pour traiter uniquement l'exemplaire périmé", "Laisser en rayon jusqu'à péremption du second", "Contacter le grossiste pour échange standard"], "r": 1, "e": "FP-STK-001 précise : 'Article duo avec un seul périmé → dépareiller si possible.' L'objectif est de ne pas perdre l'exemplaire encore valide. Seul l'exemplaire périmé passe en zone TRP.|||💡 Point pratique : Duo périmé partiel = dépareiller. Ne jamais sacrifier l'article valide par facilité.", "fiche": "FP-STK-001"}, {"t": "Procédure", "sub": "b2b_facturation", "d": "approfondi", "q": "Lors de la recherche hebdomadaire des prescriptions MRS via TUH, que faut-il noter après l'appel Recip-e ?", "a": ["Les patients avec ordonnances expirées à renouveler", "Les patients sans numéro de carte d'identité valide pour demander les numéros au MRS", "Les médicaments en rupture de stock pour la semaine suivante", "Les doublons de délivrance détectés par Recip-e"], "r": 1, "e": "FP-B2B-001 précise : après l'appel Recip-e, noter les patients sans numéro de carte d'identité valide pour demander les numéros à la MRS. Ce suivi est indispensable pour la régularisation des ordonnances.|||💡 Point pratique : Carte d'identité manquante = blocage de la régularisation. La demander proactivement au MRS évite les retards.", "fiche": "FP-B2B-001"}, {"t": "Procédure", "sub": "b2b_facturation", "d": "essentiel", "q": "Pour générer une note d'envoi dans CCP, quel chemin faut-il suivre ?", "a": ["TUH → Listes → Note d'envoi institution", "Exploitation → Facturation → Note d'envoi → Institution → exclure multidoses → intervalle de date → Appliquer → CTRL+P", "Galien → B2B → Note d'envoi → Imprimer", "Commandes → Retours → Note d'envoi grossiste"], "r": 1, "e": "FP-FACT-001 détaille le chemin : Exploitation → Facturation → Note d'envoi → Institution → exclure les articles multidoses → choisir l'intervalle de date → Appliquer → imprimer avec CTRL+P.|||💡 Point pratique : Bien exclure les multidoses — les inclure génère une note incorrecte pour l'institution.", "fiche": "FP-FACT-001"}, {"t": "Procédure", "sub": "tarification", "d": "approfondi", "q": "Selon FP-SYN-001, où faut-il vérifier les erreurs de facturation avant la clôture de période ?", "a": ["Dans CCP → Listes → Suspens/Litiges", "Dans Galien → Suivi → Vente à Facturer avec filtres : vente sans patient, patient=acheteur, type erreur, flag payé", "Dans Newsoft → Production → Erreurs de facturation", "Dans EPC → Onglet Facturation → Alertes"], "r": 1, "e": "FP-SYN-001 décrit la vérification facturation : aller dans Galien → Suivi → Vente à Facturer avec les filtres suivants : vente sans patient, patient=acheteur, toutes les ventes, type erreur, flag payé. Corriger ensuite dans CCP.|||💡 Point pratique : Galien = outil de détection des erreurs. CCP = outil de correction. Les deux logiciels sont complémentaires.", "fiche": "FP-SYN-001"}];
