const GAL_CATS = {"gal_prep_mag_off": {"label": "Préparations magistrales/officinales", "icon": "📖", "theme": "galenique"}, "gal_capsules": {"label": "Gélules & capsules", "icon": "💊", "theme": "galenique"}, "gal_rectal": {"label": "Voie rectale", "icon": "🔵", "theme": "galenique"}, "gal_ophtalmo": {"label": "Préparations ophtalmiques", "icon": "👁️", "theme": "galenique"}, "gal_orl": {"label": "Sphère ORL", "icon": "👂", "theme": "galenique"}, "gal_solutions": {"label": "Solutions", "icon": "💧", "theme": "galenique"}, "gal_emulsions": {"label": "Émulsions", "icon": "🥛", "theme": "galenique"}, "gal_suspensions": {"label": "Suspensions", "icon": "🌫️", "theme": "galenique"}, "gal_cutane": {"label": "Peau & absorption cutanée", "icon": "🧴", "theme": "galenique"}, "gal_ftm": {"label": "FTM & validité", "icon": "⏱️", "theme": "galenique"}, "gal_dermato_formes": {"label": "Formes dermatologiques", "icon": "🧪", "theme": "galenique"}, "gal_dermato_excip": {"label": "Excipients dermato", "icon": "⚗️", "theme": "galenique"}};
