// ── LOT FORMATS PÉDAGOGIQUES (VF / Erreur / Risque / Cas) ──
const FORMATS_QDB = [
  {"t":"Déontologie","sub":"deon_secret","d":"Basique","q":"✔/✘ Un pharmacien peut confirmer à l\'employeur d\'un patient qu\'il est suivi pour un traitement antidépresseur si cet employeur invoque une obligation de sécurité au travail.","a":["Vrai — la sécurité au travail prime","Faux — le secret professionnel est absolu, aucun employeur ne peut obtenir cette information"],"r":1,"e":"Le secret professionnel est absolu et s\'applique à toute personne, y compris l\'employeur. Aucun motif professionnel ou économique ne justifie la divulgation du traitement d\'un patient sans son consentement explicite. L\'employeur doit obtenir ces informations via le médecin du travail dans le cadre légal prévu.|||💡 Refuser fermement, quelle que soit la qualité de l\'interlocuteur. Rediriger vers le médecin du travail.","type_question":"vrai_faux"},
  {"t":"Déontologie","sub":"deon_continuite","d":"Expert","q":"✔/✘ En service de garde, une pharmacienne peut invoquer sa clause de conscience pour refuser de délivrer une contraception d\'urgence, même si aucune autre pharmacie n\'est accessible.","a":["Vrai — la clause de conscience est un droit inaliénable","Faux — la clause de conscience cède devant le droit à la continuité des soins en garde"],"r":1,"e":"La clause de conscience est reconnue, mais elle s\'efface systématiquement devant le droit du patient à la continuité des soins pendant le service de garde. Si aucune autre pharmacie n\'est accessible, la pharmacienne doit délivrer. La continuité des soins prime toujours en garde.|||💡 En garde sans alternative : délivrer. La clause de conscience ne s\'applique pas dans ce contexte.","type_question":"vrai_faux"},
  {"t":"BPP Officinales","sub":"bppo_locaux","d":"Basique","q":"✔/✘ Un médicament peut être rangé directement sur le comptoir, à portée de main du patient, si la pharmacie est peu fréquentée.","a":["Vrai — si la pharmacie est calme, le risque est limité","Faux — les médicaments ne doivent jamais être accessibles directement par le patient"],"r":1,"e":"Selon les BPP Officinales, la pharmacie doit être agencée de sorte que les médicaments ne se trouvent pas à portée de main du patient. Cette règle est indépendante de la fréquentation. Elle vise à prévenir tout accès non contrôlé aux médicaments.|||💡 Aucun médicament accessible directement par le patient, quel que soit le contexte.","type_question":"vrai_faux"},
  {"t":"BPP Officinales","sub":"ftm_etiquetage","d":"Intermédiaire","q":"✔/✘ L\'étiquette d\'une préparation magistrale peut ne pas mentionner la date de péremption si le prescripteur n\'en a pas précisé.","a":["Vrai — la date de péremption est facultative sans instruction du prescripteur","Faux — la date de péremption est obligatoire sur toute préparation magistrale"],"r":1,"e":"L\'étiquetage d\'une préparation magistrale est réglementé et doit obligatoirement inclure la date de péremption. En l\'absence d\'indication du prescripteur, le pharmacien la détermine selon la FTM. L\'omission constitue une non-conformité.|||💡 Date de péremption obligatoire sur toute préparation magistrale, même sans instruction du prescripteur.","type_question":"vrai_faux"},
  {"t":"Procédure","sub":"stupefiants","d":"Basique","q":"✔/✘ Depuis le 1er septembre 2023, un bon de stupéfiant papier reçu d\'un confrère peut encore être accepté à titre exceptionnel.","a":["Vrai — une tolérance exceptionnelle est prévue","Faux — les bons papier n\'ont plus aucune valeur légale depuis le 01/09/2023"],"r":1,"e":"Depuis le 1er septembre 2023, les bons de stupéfiants papier n\'ont plus aucune valeur légale chez Familia. Seule la déclaration électronique via Narcoreg est valable. Un bon papier reçu après cette date doit être refusé, quelle que soit la situation.|||💡 Tout bon papier post-01/09/2023 = aucune valeur. Uniquement Narcoreg.","type_question":"vrai_faux"},
  {"t":"Déontologie","sub":"deon_delivrance","d":"Intermédiaire","q":"✔/✘ Un pharmacien peut conseiller un complément alimentaire dont il ne connaît pas le profil d\'action si la publicité télévisée semble sérieuse.","a":["Vrai — la notoriété publicitaire est un indicateur suffisant","Faux — le pharmacien ne peut conseiller que des produits dont il connaît le profil d\'action"],"r":1,"e":"Le pharmacien ne peut conseiller que des médicaments et produits dont il connaît la qualité et le profil d\'action. Une publicité, même d\'apparence scientifique, ne constitue pas une base de conseil suffisante. Il doit se documenter objectivement avant toute recommandation.|||💡 Pas de conseil sans connaissance du profil d\'action. S\'abstenir et se documenter d\'abord.","type_question":"vrai_faux"},
  {"t":"Procédure","sub":"caisse","d":"Intermédiaire","q":"✔/✘ En cas d\'erreur lors de l\'encodage des liquidités en clôture de caisse Familia, il faut renseigner le motif de l\'erreur dans le champ \'justification de la différence\'.","a":["Vrai — justifier permet de tracer l\'erreur","Faux — il ne faut rien renseigner dans ce champ : recompter et corriger la valeur"],"r":1,"e":"Les procédures Familia précisent explicitement qu\'en cas d\'erreur, il ne faut rien renseigner dans le champ justification. La bonne action est de recompter les tiroirs et la réserve, vérifier les transactions Bancontact et corriger la valeur comptée.|||💡 Erreur en clôture = recompter, pas justifier. Laisser le champ vide.","type_question":"vrai_faux"},
  {"t":"Préparations magistrales","sub":"ftm_tracabilite","d":"Intermédiaire","q":"✔/✘ Le numéro de lot des matières premières utilisées dans une préparation magistrale doit être enregistré dans le registre de préparation.","a":["Vrai","Faux — seule la date d\'achat suffit"],"r":0,"e":"La traçabilité des matières premières est une obligation réglementaire pour toute préparation magistrale. L\'enregistrement du numéro de lot permet de retracer l\'origine de chaque composant en cas de non-conformité ou de rappel de lot. Cette traçabilité est vérifiée lors des inspections AFMPS.|||💡 Numéro de lot matière première = à enregistrer obligatoirement dans le registre de préparation.","type_question":"vrai_faux"},
  {"t":"Dermo-cosmétique","sub":"lrp","d":"Basique","q":"✔/✘ Un patient sous isotrétinoïne orale peut utiliser une crème hydratante contenant du rétinol pour potentialiser l\'effet du traitement.","a":["Vrai — le rétinol renforce l\'effet de l\'isotrétinoïne","Faux — vitamine A topique + isotrétinoïne orale est contre-indiqué"],"r":1,"e":"L\'isotrétinoïne est un dérivé de la vitamine A. Associer un cosmétique contenant du rétinol à un traitement oral par isotrétinoïne expose à une potentialisation des effets irritants et à un risque de toxicité cutanée accrue. Proposer uniquement un émollient doux sans rétinoïdes.|||💡 Isotrétinoïne orale + vitamine A topique = contre-indiqué. Émollient doux sans rétinoïde uniquement.","type_question":"vrai_faux"},
  {"t":"Conseil officinal","sub":"gastro","d":"Intermédiaire","q":"✔/✘ Face à un patient qui achète régulièrement de grandes quantités de lopéramide OTC, le pharmacien peut continuer à délivrer librement car le patient adulte est responsable de ses choix.","a":["Vrai — l\'autonomie du patient prime","Faux — le pharmacien doit intervenir face à une surconsommation avérée"],"r":1,"e":"Le pharmacien a l\'obligation déontologique d\'intervenir face à une surconsommation avérée ou suspectée. Il doit prendre les initiatives nécessaires : dialogue bienveillant, limitation des quantités, orientation vers le médecin. Rester passif face à un mésusage constitue un manquement professionnel grave.|||💡 Surconsommation suspectée = dialogue obligatoire. Le libre choix du patient ne prime pas sur la sécurité.","type_question":"vrai_faux"},
  {"t":"Procédure","sub":"stupefiants","d":"Basique","q":"🔍 Une pharmacie reçoit le 15 octobre une ordonnance de méthadone. Le patient ne s\'est pas présenté depuis 4 jours consécutifs. Le pharmacien continue de conserver la méthadone et attend le retour sans contacter le médecin. Quelle est l\'erreur principale ?","a":["Refuser la délivrance dès le premier jour d\'absence","Ne pas avoir contacté le médecin après 3 jours consécutifs d\'absence","Signaler l\'absence directement à l\'AFMPS","Conserver la méthadone maximum 2 jours seulement"],"r":1,"e":"Selon la convention Familia pour les traitements de substitution, le pharmacien peut refuser de délivrer si le patient ne se présente pas pendant 3 jours consécutifs pour la méthadone, et doit contacter le médecin. Après 3 jours sans présentation, l\'inaction constitue une erreur.|||💡 Méthadone : 3 jours sans présentation = stopper et appeler le médecin sans délai.","type_question":"trouver_erreur"},
  {"t":"Préparations magistrales","sub":"ftm_etiquetage","d":"Intermédiaire","q":"🔍 Un pharmacien prépare une crème magistrale. Il appose sur le conditionnement : le nom du patient, la date de préparation, la composition et la posologie. Il remet la préparation au patient avec une notice. Quelle est l\'erreur principale ?","a":["La notice n\'aurait pas dû être remise séparément","La date de péremption est absente de l\'étiquette","Le nom du dermatologue prescripteur est absent","La voie d\'administration n\'est pas précisée"],"r":1,"e":"L\'étiquetage obligatoire d\'une préparation magistrale doit inclure la date de péremption. Son absence constitue une non-conformité réglementaire majeure. Les autres éléments cités sont utiles mais l\'absence de péremption est l\'erreur la plus critique car elle peut engager la sécurité du patient.|||💡 Date de péremption = mention obligatoire sur toute étiquette de préparation magistrale.","type_question":"trouver_erreur"},
  {"t":"BPP Officinales","sub":"bppo_locaux","d":"Basique","q":"🔍 Un pharmacien loue un espace à un médecin généraliste pour des consultations le mardi après-midi. Il justifie cela par l\'intérêt pour les patients. Quelle est l\'erreur principale ?","a":["Le médecin aurait dû signer une convention écrite","La location d\'espace à un tiers dans la pharmacie est interdite sans autorisation préalable du Conseil national","Les patients auraient dû être informés que le médecin n\'est pas employé par la pharmacie","La consultation médicale n\'est pas une activité autorisée en pharmacie"],"r":1,"e":"Le code de déontologie interdit au pharmacien de mettre à disposition de tiers un espace de la pharmacie sous quelque condition que ce soit. Une exception ne peut être accordée que préalablement par le Conseil national dans le cadre strict d\'initiatives de santé publique.|||💡 Toute mise à disposition d\'espace à un tiers exige une autorisation préalable du Conseil national.","type_question":"trouver_erreur"},
  {"t":"Déontologie","sub":"deon_secret","d":"Intermédiaire","q":"🔍 Un pharmacien constate que son logiciel transmet des données patients à une société partenaire pour analyse marketing. Il informe l\'éditeur par email et lui demande de corriger cela lors de la prochaine mise à jour dans 3 mois. Quelle est l\'erreur principale ?","a":["Le pharmacien n\'a pas informé les patients concernés","Le pharmacien aurait dû d\'abord consulter l\'Ordre","Le pharmacien n\'a pas exigé l\'arrêt immédiat de la transmission","Le pharmacien n\'a pas vérifié le consentement des patients"],"r":2,"e":"Dès qu\'il a connaissance d\'une pratique non conforme, le pharmacien doit prendre toutes les mesures nécessaires pour la faire cesser immédiatement. Attendre 3 mois pour une correction de routine est inacceptable. Toute transmission non autorisée de données patients constitue une violation du RGPD et du secret professionnel.|||💡 Transmission illicite de données = arrêt immédiat exigé, pas lors de la prochaine mise à jour.","type_question":"trouver_erreur"},
  {"t":"Procédure","sub":"caisse","d":"Basique","q":"🔍 En fin de journée, la pharmacienne réalise la clôture de caisse. Elle clique sur \'Fin\' directement après avoir vérifié le montant. Elle imprimera le rapport de clôture le lendemain matin si nécessaire. Quelle est l\'erreur principale ?","a":["La clôture de caisse doit se faire en fin de semaine, pas chaque jour","La case \'Impression du rapport de clôture de caisse\' doit être cochée avant de cliquer sur \'Fin\'","La vérification du montant doit se faire après avoir cliqué sur \'Fin\'","Le rapport de clôture doit être signé par deux pharmaciens"],"r":1,"e":"Les Bonnes Pratiques de gestion Familia précisent que la case \'Impression du rapport de clôture de caisse\' doit être cochée avant de cliquer sur \'Fin\'. Sans cette impression, il n\'y a pas de traçabilité de la clôture journalière. Remettre cette étape au lendemain n\'est pas acceptable.|||💡 Cocher \'Impression rapport clôture\' AVANT de cliquer sur Fin. Sans ça, pas de traçabilité.","type_question":"trouver_erreur"},
  {"t":"Médicaments","sub":"cbip","d":"Intermédiaire","q":"🔍 Un patient sous metformine 1000 mg 2x/j doit passer un scanner avec injection de produit de contraste iodé dans 3 jours. Il présente son courrier de convocation. Le pharmacien lui dit que tout va bien et qu\'il peut continuer son traitement normalement. Quelle est l\'erreur principale ?","a":["La metformine ne pose aucun problème avec les produits de contraste","La metformine doit être arrêtée 48h avant et 48h après l\'injection de produit de contraste iodé","Le pharmacien aurait dû proposer un substitut à la metformine","Le patient doit être à jeun mais peut prendre sa metformine"],"r":1,"e":"L\'association metformine + produit de contraste iodé expose à un risque d\'acidose lactique en cas d\'insuffisance rénale aiguë post-injection. Le protocole standard recommande d\'arrêter la metformine 48h avant et de ne la reprendre que 48h après l\'examen, après vérification de la fonction rénale.|||💡 Scanner injecté + metformine = arrêt 48h avant et 48h après. Toujours vérifier à la délivrance.","sys":"endocrino","type_question":"trouver_erreur"},
  {"t":"Conseil officinal","sub":"orl","d":"Intermédiaire","q":"🔍 Un patient de 72 ans reçoit une nouvelle prescription d\'amiodarone. Son dossier pharmaceutique montre qu\'il est sous warfarine depuis 2 ans. Le pharmacien délivre les deux médicaments en se disant que le médecin a sûrement tenu compte de cette association. Quelle est l\'erreur principale ?","a":["Amiodarone et warfarine sont contre-indiquées ensemble","Le pharmacien doit contacter le prescripteur : l\'amiodarone peut tripler l\'INR","Le pharmacien aurait dû proposer de remplacer la warfarine par un NOAC","Un patient de 72 ans ne peut pas recevoir d\'amiodarone"],"r":1,"e":"L\'amiodarone inhibe le métabolisme de la warfarine et peut tripler l\'INR, avec un risque hémorragique majeur. Le pharmacien ne doit pas présumer que le médecin a géré cette interaction : il doit le contacter pour confirmer l\'adaptation posologique et la surveillance de l\'INR.|||💡 Amiodarone + warfarine = contact prescripteur obligatoire. L\'INR peut tripler. Surveillance renforcée.","type_question":"trouver_erreur"},
  {"t":"Dermo-cosmétique","sub":"lrp","d":"Basique","q":"🔍 Une pharmacie affiche en vitrine une publicité pour une gamme de soins solaires. La publicité a été installée par le délégué du laboratoire qui a proposé en échange une remise sur commande. Quelle est l\'erreur principale ?","a":["La publicité pour des produits solaires est interdite en officine","Le pharmacien a accepté un avantage commercial conditionné, compromettant son indépendance","Le pharmacien aurait dû demander l\'autorisation de l\'Ordre avant d\'afficher","La publicité en vitrine ne doit pas dépasser une certaine surface"],"r":1,"e":"Accepter une remise sur commande en contrepartie d\'une mise en avant commerciale constitue une collusion interdite et compromet l\'indépendance professionnelle du pharmacien. Même pour des produits dermo-cosmétiques, une publicité conditionnée à un avantage financier viole le code de déontologie.|||💡 Remise conditionnée à une mise en avant = collusion interdite, quelle que soit la forme.","type_question":"trouver_erreur"},
  {"t":"Procédure","sub":"commandes","d":"Intermédiaire","q":"🔍 Un pharmacien souhaite délocaliser dans CCP un article du robot. Il décocke \'localisé\' dans la fiche article, puis vérifie ensuite via Q.St que le robot est vide de ce produit. Quelle est l\'erreur principale ?","a":["Il aurait dû faire la vérification Q.St avant de décocher \'localisé\'","La délocalisation ne peut se faire que via Galien, pas CCP","Il faut informer le service technique avant toute délocalisation","La vérification Q.St doit être faite après validation par le titulaire"],"r":0,"e":"La procédure CFPQ Robot impose un ordre strict : d\'abord vérifier via Q.St que le robot est vide du produit, puis décocher \'localisé\' dans la fiche article. Inverser l\'ordre crée une incohérence de stock et peut générer des erreurs d\'inventaire et des ruptures fictives.|||💡 Ordre impératif : Q.St vide → décocher localisé. Jamais dans l\'autre sens.","type_question":"trouver_erreur"},
  {"t":"Conseil officinal","sub":"autres","d":"Basique","q":"🔍 Un patient demande au pharmacien pourquoi son médecin lui a prescrit de l\'amlodipine plutôt que du ramipril. Le pharmacien exprime sa préférence pour les IEC et souligne que les inhibiteurs calciques sont moins bien tolérés en général. Quelle est l\'erreur principale ?","a":["Le pharmacien n\'aurait pas dû répondre à cette question","Le pharmacien a ébranlé la confiance du patient envers le prescripteur","Le pharmacien aurait dû recommander de changer de médecin","Le pharmacien n\'a pas proposé une alternative thérapeutique valide"],"r":1,"e":"Le pharmacien doit informer le patient sur son médicament sans ébranler la confiance envers le prescripteur. Exprimer une préférence personnelle et sous-entendre que le choix du médecin est moins bon constitue une erreur déontologique. Il doit expliquer le médicament prescrit et renvoyer les questions de choix thérapeutique vers le médecin.|||💡 Expliquer le médicament prescrit, jamais remettre en cause le choix du prescripteur devant le patient.","type_question":"trouver_erreur"},
  {"t":"Médicaments","sub":"cbip","d":"Intermédiaire","q":"⚠️ Quelle situation présente le risque hémorragique le plus important ?","a":["Patient sous ibuprofène OTC pour douleur dentaire occasionnelle","Patient sous warfarine qui achète de l\'aspirine 500 mg OTC pour un mal de tête","Patient sous metformine qui prend un antiacide en automédication","Patient sous amlodipine qui consomme du jus de pamplemousse 1 fois/semaine"],"r":1,"e":"L\'association warfarine + aspirine présente le risque hémorragique le plus élevé : potentialisation de l\'effet anticoagulant et risque de saignement majeur. C\'est une interaction à éviter absolument. Les autres situations présentent des risques réels mais bien moins critiques.|||💡 Anticoagulant + AINS ou aspirine = risque hémorragique majeur. Vérifier systématiquement le traitement de fond.","sys":"hemato","type_question":"detection_risque"},
  {"t":"Procédure","sub":"stupefiants","d":"Expert","q":"⚠️ Quelle situation présente le risque vital immédiat le plus important pour un patient sous traitement de substitution ?","a":["Patient sous méthadone se présentant le lendemain de sa dernière délivrance","Patient sous buprénorphine absent depuis 4 jours consécutifs","Patient sous méthadone présentant des signes visibles d\'intoxication alcoolique","Patient sous traitement de substitution dont l\'ordonnance est valable encore 2 jours"],"r":2,"e":"Un patient sous méthadone présentant des signes d\'intoxication alcoolique représente le risque le plus immédiat : l\'association méthadone + alcool est potentiellement mortelle par dépression respiratoire. La convention Familia impose de refuser la délivrance et de contacter le médecin immédiatement.|||💡 Intoxication visible + opioïde = refus de délivrance immédiat + appel médecin. Risque vital.","type_question":"detection_risque"},
  {"t":"Médicaments","sub":"cbip","d":"Intermédiaire","q":"⚠️ Quelle situation présente le risque sérotoninergique le plus élevé ?","a":["Patient âgé de 75 ans sous amlodipine qui signale des oedèmes des chevilles","Patient sous ISRS qui commence un traitement par tramadol prescrit par un autre médecin","Patient sous metformine qui suit un régime hypocalorique strict","Patient sous paracétamol qui prend également de la vitamine C à haute dose"],"r":1,"e":"L\'association ISRS + tramadol présente un risque sérotoninergique majeur pouvant mener à un syndrome sérotoninergique sévère, potentiellement fatal. C\'est une interaction qui doit alerter le pharmacien même quand les prescripteurs sont différents.|||💡 ISRS + tramadol = syndrome sérotoninergique possible. Vérifier le dossier pharmaceutique complet.","sys":"neuro","type_question":"detection_risque"},
  {"t":"Déontologie","sub":"deon_independance","d":"Intermédiaire","q":"⚠️ Quelle situation présente le risque déontologique le plus grave ?","a":["Un pharmacien titulaire salarié qui ne relit pas les publicités diffusées par la chaîne","Un pharmacien qui réfère systématiquement ses patients vers une clinique en échange d\'une commission sur les actes","Un pharmacien qui accepte d\'afficher une brochure non sollicitée d\'un laboratoire","Un pharmacien qui recommande en priorité les génériques pour maîtriser les dépenses"],"r":1,"e":"Une commission sur les actes en échange d\'orientations de patients constitue une collusion directe entre pharmacien et professionnel de santé, formellement interdite. Cela porte atteinte à l\'indépendance professionnelle, au libre choix du patient et à la qualité des soins.|||💡 Tout accord financier liant orientation des patients = collusion interdite. Signaler à l\'Ordre si nécessaire.","type_question":"detection_risque"},
  {"t":"Procédure","sub":"caisse","d":"Intermédiaire","q":"⚠️ Quelle situation engage la responsabilité financière personnelle du pharmacien responsable de journée selon les procédures Familia ?","a":["Un report de la clôture de caisse du vendredi soir au lundi matin","Une dépense de caisse remboursée sans justificatif papier daté et signé","Un montant en caisse légèrement supérieur au seuil autorisé","Une transaction Bancontact non vérifiée lors de la clôture"],"r":1,"e":"Toute dépense de caisse non justifiée par une preuve est à charge personnelle du pharmacien responsable de la journée. Ce risque est explicitement documenté dans les procédures Familia. Les autres situations sont des irrégularités, mais la dépense non justifiée engage la responsabilité financière personnelle de façon directe et immédiate.|||💡 Chaque dépense de caisse doit avoir un justificatif daté et signé. La responsabilité personnelle est engagée.","type_question":"detection_risque"},
  {"t":"Préparations magistrales","sub":"ftm_tracabilite","d":"Expert","q":"⚠️ Quelle situation présente le risque qualité le plus élevé dans une préparation magistrale ?","a":["Péremption calculée par le pharmacien sans consultation de la FTM","Numéro de lot des matières premières non enregistré","Dépassement de 2% de la quantité théorique en matière active","Préparation réalisée dans un mortier non nettoyé depuis la veille"],"r":3,"e":"Un mortier non nettoyé constitue un risque de contamination croisée direct et immédiat pour la préparation en cours. Ce risque peut rendre la préparation inutilisable ou dangereuse. Les autres situations présentent des non-conformités réglementaires sérieuses mais qui ne compromettent pas nécessairement la sécurité immédiate du patient.|||💡 Tout matériel de préparation magistrale doit être nettoyé et validé avant usage. Contamination croisée = risque direct.","type_question":"detection_risque"},
  {"t":"BPP Officinales","sub":"bppo_stock","d":"Intermédiaire","q":"⚠️ Quelle situation présente le risque de rupture de chaîne du froid le plus important ?","a":["Un médicament réfrigéré sorti du frigo 10 minutes avant la délivrance","Un médicament réfrigéré retrouvé sur le comptoir 2 heures après réception d\'une livraison","Un vaccin stocké dans un frigo à 6°C au lieu de 4°C","Un médicament réfrigéré dont l\'emballage présente une légère condensation"],"r":1,"e":"Un médicament réfrigéré laissé sur le comptoir 2 heures présente le risque le plus élevé de rupture de chaîne du froid. La dégradation peut être irréversible et le médicament peut ne plus être efficace ou devenir dangereux. Les autres situations sont des écarts mineurs ou à surveiller.|||💡 Médicament froid laissé à température ambiante plus d\'1h = ne pas utiliser, contacter le fournisseur.","type_question":"detection_risque"},
  {"t":"Médicaments","sub":"cbip","d":"Expert","q":"⚠️ Quelle situation présente le risque tératogène le plus élevé ?","a":["Femme en T2 sous paracétamol 1g 3x/j pour douleurs dorsales","Femme en T1 qui prend de l\'ibuprofène 400 mg ponctuellement pour une migraine","Femme de 28 ans en âge de procréer sous rétinoïdes oraux sans contraception efficace documentée","Femme allaitante sous amoxicilline pour une infection dentaire"],"r":2,"e":"Les rétinoïdes oraux sont parmi les substances les plus tératogènes connues. Une femme en âge de procréer sous ce traitement doit disposer d\'une contraception efficace et documentée. L\'absence de cette documentation représente un risque tératogène extrême. Les autres situations présentent des risques bien moindres.|||💡 Rétinoïdes oraux + femme en âge de procréer = contraception efficace OBLIGATOIRE. Vérifier à chaque délivrance.","sys":"gyneco_uro","type_question":"detection_risque"},
  {"t":"Dermo-cosmétique","sub":"cerave","d":"Basique","q":"⚠️ Quelle situation présente le risque conseil le plus important en dermo-cosmétique ?","a":["Conseiller un soin hydratant quotidien à une femme enceinte au T3","Conseiller un produit solaire SPF 50 à un patient sous méthotrexate sans l\'alerter sur la photosensibilisation","Conseiller un gel nettoyant doux à un adolescent avec peau grasse","Conseiller une crème anti-âge avec rétinol à une femme de 55 ans"],"r":1,"e":"Le méthotrexate est photosensibilisant. Le vrai risque ici est de ne pas alerter le patient sur la nécessité d\'une protection solaire renforcée et systématique en raison de la photosensibilisation médicamenteuse. Un simple conseil SPF 50 sans explication adaptée au contexte thérapeutique est insuffisant.|||💡 Patient sous méthotrexate = photosensibilisation. Protection solaire maximale et systématique à conseiller.","type_question":"detection_risque"},
  {"t":"Conseil officinal","sub":"gastro","d":"Intermédiaire","q":"⚠️ Quelle situation présente le risque de non-intervention le plus grave pour le pharmacien ?","a":["Patient qui achète un antiacide en automédication pour brûlures d\'estomac occasionnelles","Patient qui achète régulièrement depuis 3 mois du lopéramide en grande quantité","Patient qui achète de la mélatonine 1 mg pour des troubles du sommeil ponctuels","Patient qui achète du sérum physiologique pour rinçage nasal quotidien"],"r":1,"e":"L\'achat répété et en grande quantité de lopéramide évoque un mésusage ou une dépendance potentielle. Le pharmacien a l\'obligation d\'intervenir, d\'instaurer un dialogue bienveillant et d\'orienter vers un médecin si nécessaire. Ne pas intervenir face à une surconsommation avérée constitue un manquement déontologique grave.|||💡 Achat répété et en quantité anormale d\'un OTC = signal d\'alerte. Dialogue obligatoire.","type_question":"detection_risque"},
  {"t":"Conseil officinal","sub":"gyneco","d":"Intermédiaire","q":"[CAS Grossesse & médicaments — étape 1/3] Mme D., 32 ans, enceinte de 8 semaines, se présente avec une prescription de sertraline 50 mg/j pour un épisode dépressif. Elle n\'a pas encore informé son gynécologue de ce traitement. Quelle est la première action prioritaire du pharmacien ?","a":["Refuser la délivrance : la sertraline est contre-indiquée au T1","Délivrer sans commentaire, le prescripteur a évalué le rapport bénéfice/risque","Délivrer avec information sur les précautions au T1 et conseiller d\'informer le gynécologue","Proposer une alternative non médicamenteuse à la sertraline"],"r":2,"e":"La sertraline n\'est pas contre-indiquée au T1, mais nécessite une surveillance particulière. Le pharmacien doit délivrer avec une information claire sur les précautions en grossesse et s\'assurer que le gynécologue est informé pour une coordination optimale des soins. Refuser est inapproprié, délivrer silencieusement est insuffisant.|||💡 Tout médicament en T1 = information sur les précautions + coordination avec le gynécologue.","type_question":"cas_evolutif"},
  {"t":"Conseil officinal","sub":"gyneco","d":"Intermédiaire","q":"[CAS Grossesse & médicaments — étape 2/3] En discutant, Mme D. mentionne qu\'elle prend également de l\'ibuprofène 400 mg ponctuellement pour des maux de tête depuis le début de sa grossesse. Quelle est la conduite à tenir ?","a":["Rassurer la patiente : l\'ibuprofène est sans risque au T1","Déconseiller formellement l\'ibuprofène en grossesse et proposer le paracétamol","Conseiller de ne prendre l\'ibuprofène qu\'en cas de douleur très intense","Informer uniquement le prescripteur de la sertraline de la prise d\'ibuprofène"],"r":1,"e":"Les AINS, dont l\'ibuprofène, sont déconseillés dès le T1 et contre-indiqués à partir du T2 en raison des risques fœtaux. Le paracétamol reste l\'antalgique de référence en grossesse. Il faut informer clairement la patiente et proposer une alternative adaptée.|||💡 AINS déconseillés dès le T1 en grossesse. Paracétamol = antalgique de référence.","type_question":"cas_evolutif"},
  {"t":"Conseil officinal","sub":"gyneco","d":"Expert","q":"[CAS Grossesse & médicaments — étape 3/3] Mme D. revient 2 mois plus tard (T2). Elle a une ordonnance de sertraline 100 mg + zopiclone 7,5 mg. Elle demande aussi si elle peut continuer l\'ibuprofène qu\'elle a chez elle. Quelle est la priorité absolue du pharmacien ?","a":["Délivrer les deux médicaments prescrits et rappeler que l\'ibuprofène est déconseillé","Délivrer uniquement la sertraline et refuser la zopiclone","Refuser les deux médicaments et contacter immédiatement le prescripteur","Contacter le prescripteur avant toute délivrance : zopiclone et ibuprofène posent tous deux problème au T2"],"r":3,"e":"Au T2, l\'ibuprofène est contre-indiqué (toxicité fœtale). La zopiclone est déconseillée en grossesse. La prescription cumule deux problèmes sérieux. Le pharmacien doit contacter le prescripteur avant de délivrer. C\'est une situation d\'urgence déontologique et de sécurité.|||💡 Toute prescription en grossesse = vérification systématique de chaque médicament selon le trimestre.","type_question":"cas_evolutif"},
  {"t":"Procédure","sub":"stupefiants","d":"Intermédiaire","q":"[CAS Ordonnance suspecte — étape 1/3] M. T., patient régulier sous méthadone depuis 18 mois, se présente avec une ordonnance signée par un médecin inconnu de la pharmacie. L\'ordonnance est datée d\'aujourd\'hui mais le nom du médecin ne correspond pas au suivi habituel. Quelle est la première action du pharmacien ?","a":["Refuser la délivrance : le médecin n\'est pas connu","Délivrer normalement : l\'ordonnance est en règle et le patient est connu","Contacter le médecin habituel du patient pour vérifier le changement de suivi","Demander au patient d\'expliquer le changement de médecin avant de délivrer"],"r":2,"e":"Un changement de prescripteur pour un traitement de substitution est un signal d\'alerte. Le pharmacien doit contacter le médecin habituel pour vérifier si le transfert de suivi est officiel et coordonné. Délivrer sans vérification exposerait le patient à un suivi non coordonné ou à une fraude.|||💡 Changement de prescripteur TSO = contacter le médecin habituel avant toute délivrance.","type_question":"cas_evolutif"},
  {"t":"Procédure","sub":"stupefiants","d":"Intermédiaire","q":"[CAS Ordonnance suspecte — étape 2/3] Le médecin habituel confirme qu\'il n\'a pas organisé de transfert et qu\'il suit toujours M. T. Il suspecte une falsification d\'ordonnance. M. T. attend toujours au comptoir. Quelle est la conduite à tenir immédiatement ?","a":["Délivrer quand même pour ne pas priver le patient de son traitement","Refuser la délivrance, conserver l\'ordonnance et informer le médecin habituel","Appeler la police avant de dire quoi que ce soit au patient","Remettre l\'ordonnance au patient et lui demander de recontacter son médecin"],"r":1,"e":"Face à une suspicion de falsification confirmée par le prescripteur, le pharmacien doit refuser la délivrance et conserver l\'ordonnance suspecte. Il informe le médecin habituel. Conserver l\'ordonnance est une démarche légale qui permet un suivi ultérieur et protège les preuves.|||💡 Ordonnance suspecte = refus de délivrance + conservation de l\'ordonnance + contact médecin habituel.","type_question":"cas_evolutif"},
  {"t":"Procédure","sub":"stupefiants","d":"Expert","q":"[CAS Ordonnance suspecte — étape 3/3] M. T. devient agressif et exige son traitement, expliquant qu\'il sera en manque dans quelques heures. Quelle est l\'attitude déontologiquement correcte ?","a":["Délivrer une dose de secours pour éviter le syndrome de sevrage","Maintenir le refus, rester calme et orienter vers les urgences médicales ou le médecin habituel","Appeler immédiatement les services d\'urgence psychiatriques","Proposer une alternative de substitution en attendant la régularisation"],"r":1,"e":"La pression ou l\'agressivité ne modifient jamais les règles de délivrance. Le pharmacien maintient son refus, reste calme et professionnellement ferme. Il oriente vers le médecin habituel ou les urgences médicales. Délivrer sous pression avec une ordonnance suspecte engage une responsabilité pénale grave.|||💡 Ordonnance suspecte de stupéfiant = refus maintenu quelle que soit la pression exercée.","type_question":"cas_evolutif"},
  {"t":"Préparations magistrales","sub":"ftm_etiquetage","d":"Expert","q":"[CAS Préparation magistrale — étape 1/3] Un dermatologue prescrit une crème magistrale (Urée 10% + Acide salicylique 5% + crème de base qsp 100g). Le pharmacien ne dispose pas de la FTM correspondante. Quelle est la première action ?","a":["Réaliser la préparation selon les proportions indiquées par le prescripteur","Refuser la préparation et demander une autre prescription","Consulter la FTM ou contacter le CTPP avant de réaliser la préparation","Préparer en doublant les contrôles de pesée pour compenser l\'absence de FTM"],"r":2,"e":"La FTM est la référence pour les préparations magistrales en Belgique. En l\'absence de monographie, le pharmacien doit consulter la FTM ou contacter le Centre de Pharmacie Clinique (CTPP) avant de préparer. Réaliser une préparation sans référence documentée expose à des risques de qualité et de responsabilité.|||💡 Pas de FTM disponible = consulter la FTM en ligne ou contacter le CTPP avant toute préparation.","type_question":"cas_evolutif"},
  {"t":"Préparations magistrales","sub":"ftm_etiquetage","d":"Expert","q":"[CAS Préparation magistrale — étape 2/3] La FTM est trouvée. La préparation est réalisée. Au moment de l\'étiquetage, le pharmacien hésite sur la durée de validité : la FTM indique \'3 mois\' mais la préparation sera probablement utilisée en 4 à 6 semaines. Quelle durée doit-il indiquer ?","a":["6 semaines, correspondant à l\'usage prévisible","3 mois, conformément à la FTM","6 mois, pour plus de sécurité","Pas de date : la durée dépend du patient"],"r":1,"e":"Le pharmacien doit indiquer la durée de validité selon les données de la FTM, soit 3 mois. Il ne peut pas modifier cette durée selon l\'usage présumé du patient. La durée de validité est une donnée de sécurité objective, pas une estimation de l\'usage.|||💡 Durée de validité = toujours selon la FTM. Jamais adaptée à l\'usage présumé du patient.","type_question":"cas_evolutif"},
  {"t":"Préparations magistrales","sub":"ftm_etiquetage","d":"Expert","q":"[CAS Préparation magistrale — étape 3/3] La patiente vient chercher sa crème. Elle demande si elle peut partager le reste avec sa sœur qui a le même problème de peau. Quelle est la réponse du pharmacien ?","a":["Oui, si les symptômes sont identiques","Non : une préparation magistrale est nominative et ne peut être utilisée que par le patient pour qui elle a été préparée","Oui, à condition que la sœur n\'ait pas d\'allergie connue à l\'acide salicylique","Oui, si le dermatologue donne son accord par téléphone"],"r":1,"e":"Une préparation magistrale est préparée spécifiquement pour un patient désigné, sur base d\'une prescription individuelle. Elle ne peut être utilisée que par ce patient. La céder à un tiers, même un proche avec des symptômes similaires, est contraire aux règles réglementaires et déontologiques.|||💡 Préparation magistrale = nominative. Ne peut jamais être partagée, même à un proche.","type_question":"cas_evolutif"},
  {"t":"Déontologie","sub":"deon_ethique","d":"Intermédiaire","q":"[CAS Adjoint & titulaire — étape 1/3] M. K., pharmacien adjoint, constate que le titulaire lui demande régulièrement de signer des bordereaux de délivrance pour des médicaments qu\'il n\'a pas lui-même préparés ni supervisés. Quelle est l\'attitude déontologiquement correcte ?","a":["Accepter si le titulaire garantit que les délivrances ont bien eu lieu","Accepter pour préserver la relation de travail, en gardant une trace personnelle","Refuser : signer engage sa responsabilité déontologique et pénale pour des actes non accomplis","Accepter uniquement pour des médicaments courants sans risque particulier"],"r":2,"e":"Le pharmacien adjoint est personnellement responsable des actes qu\'il certifie par sa signature. Signer pour des actes non accomplis ou non supervisés constitue une fausse certification. Le code de déontologie garantit l\'indépendance professionnelle de l\'adjoint, y compris dans sa relation avec le titulaire.|||💡 Ne jamais signer un acte pharmaceutique qu\'on n\'a pas soi-même accompli ou supervisé.","type_question":"cas_evolutif"},
  {"t":"Déontologie","sub":"deon_ethique","d":"Intermédiaire","q":"[CAS Adjoint & titulaire — étape 2/3] M. K. refuse. Le titulaire insiste en disant que c\'est \'la procédure interne\' et que tous les adjoints précédents l\'avaient fait. Que doit faire M. K. ?","a":["Accepter si c\'est une procédure interne officielle","Accepter pour ne pas créer de conflit et chercher un autre emploi rapidement","Maintenir son refus : aucune procédure interne ne prime sur l\'obligation déontologique","Demander à voir la procédure écrite avant de décider"],"r":2,"e":"Aucune procédure interne, aucun argument d\'usage ou de tradition ne peut primer sur les obligations déontologiques et légales du pharmacien. Le fait que des prédécesseurs aient accepté ne constitue pas une légitimité. M. K. doit maintenir son refus, indépendamment de la pression exercée.|||💡 Aucune procédure interne ne peut primer sur les obligations déontologiques du pharmacien.","type_question":"cas_evolutif"},
  {"t":"Déontologie","sub":"deon_ethique","d":"Intermédiaire","q":"[CAS Adjoint & titulaire — étape 3/3] M. K. maintient son refus. La situation perdure depuis 3 semaines et devient conflictuelle. Quel recours déontologique M. K. peut-il exercer ?","a":["Porter plainte directement auprès de la police","Saisir le Conseil provincial de l\'Ordre des Pharmaciens","Contacter directement l\'AFMPS","Envoyer un email à Familia Group pour signaler la situation"],"r":1,"e":"En cas de conflit déontologique persistant avec le titulaire, le pharmacien adjoint peut saisir le Conseil provincial de l\'Ordre des Pharmaciens. L\'Ordre est l\'instance compétente pour traiter les manquements déontologiques et peut être saisi pour un avis ou une médiation.|||💡 Conflit déontologique persistant avec le titulaire = saisir le Conseil provincial de l\'Ordre.","type_question":"cas_evolutif"},
  {"t":"Conseil officinal","sub":"autres","d":"Intermédiaire","q":"[CAS Patient âgé & automédication — étape 1/3] M. D., 82 ans, vivant seul, vient chercher ses médicaments habituels (amlodipine, atorvastatine, pantoprazole). Il demande aussi quelque chose contre le rhume des foins et propose lui-même de la diphenhydramine \'car ça marche bien\'. Quelle est l\'attitude correcte ?","a":["Délivrer la diphenhydramine : le patient la connaît et la tolère bien","Déconseiller la diphenhydramine chez ce patient âgé et proposer un antihistaminique non sédatif","Proposer de la diphenhydramine à demi-dose pour réduire les effets secondaires","Orienter directement vers le médecin sans donner de conseil"],"r":1,"e":"La diphenhydramine est un antihistaminique de première génération avec des propriétés anticholinergiques marquées. Chez les personnes âgées, elle est déconseillée (liste Beers) en raison du risque de confusion, de chutes, de rétention urinaire et d\'aggravation cognitive. Un antihistaminique de 2e génération (loratadine, cétirizine) est préférable.|||💡 Antihistaminique 1G chez le patient âgé = déconseillé. Toujours proposer un antihistaminique 2G non sédatif.","type_question":"cas_evolutif"},
  {"t":"Conseil officinal","sub":"autres","d":"Intermédiaire","q":"[CAS Patient âgé & automédication — étape 2/3] M. D. accepte la loratadine. En passant en revue son traitement, le pharmacien note qu\'il prend du lopéramide depuis 3 semaines \'pour un problème de diarrhée\', sans prescription. Quel est le signal d\'alerte principal ?","a":["La loratadine et le lopéramide peuvent interagir","Une diarrhée persistante de 3 semaines chez un patient de 82 ans nécessite une évaluation médicale","Le lopéramide n\'est pas adapté aux patients sous statines","Le lopéramide peut interagir avec le pantoprazole"],"r":1,"e":"Une diarrhée persistant depuis 3 semaines chez un patient de 82 ans est un symptôme d\'alerte qui dépasse l\'automédication. Elle peut cacher une pathologie sérieuse (colite, cancer colorectal, infection, effets médicamenteux). Le lopéramide en automédication prolongée masque le symptôme sans traiter la cause.|||💡 Diarrhée persistante > 2 semaines chez la personne âgée = orienter vers le médecin. Pas d\'automédication prolongée.","type_question":"cas_evolutif"},
  {"t":"Conseil officinal","sub":"autres","d":"Intermédiaire","q":"[CAS Patient âgé & automédication — étape 3/3] M. D. a aussi des difficultés à dormir depuis le début de son traitement par amlodipine et demande \'quelque chose de fort\' pour dormir. Quelle est l\'attitude correcte ?","a":["Proposer de la mélatonine à faible dose et expliquer pourquoi les somnifères forts sont dangereux chez lui","Déconseiller tout somnifère : les benzodiazépines sont formellement contre-indiquées chez ce patient","Proposer un somnifère doux à base de plantes","Délivrer un somnifère léger en lui recommandant de ne l\'utiliser que 2 fois par semaine"],"r":0,"e":"Chez un patient de 82 ans vivant seul, la mélatonine à faible dose est une option acceptable comme première intention. Les benzodiazépines et hypnotiques puissants sont à éviter (risque de chutes, confusion). Le pharmacien doit proposer une alternative raisonnable et expliquer pourquoi les somnifères forts sont dangereux.|||💡 Patient âgé + insomnie : mélatonine 1 mg en premier recours. Benzodiazépines = contre-indiquées.","type_question":"cas_evolutif"}
];
QDB.push(...FORMATS_QDB);
// ── RETOURS & TRANSFERTS (fiche pratique 21/04/2026) ──
const RETOURS_QDB = [
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Quel jour du mois les officines Familia reçoivent-elles le listing des articles pouvant faire l\'objet d\'un retour vendable ?","a":["Le premier lundi du mois","Le dernier mardi du mois","Le premier vendredi du mois","Le 20 du mois"],"r":0,"e":"Le premier lundi du mois, les officines reçoivent par mail le listing des articles pouvant être retournés (retours vendables). Le dernier mardi du mois, les officines réceptrices reçoivent ces articles si elles ont le potentiel de vente.|||💡 Premier lundi = listing retours vendables reçu. Dernier mardi = articles envoyés aux officines réceptrices.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Quelle est la validité minimale requise pour qu\'un article puisse être inclus dans un retour vendable Familia ?","a":["4 mois","6 mois","8 mois","12 mois"],"r":2,"e":"Pour être accepté dans un retour vendable, un article doit avoir une validité minimum de 8 mois restante. En dessous de ce seuil, l\'article ne peut pas être retourné comme vendable et doit suivre la procédure de retour non-vendable.|||💡 Retour vendable : validité minimum 8 mois. En dessous = retour non-vendable.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Avant quelle date du mois les articles d\'un retour vendable doivent-ils impérativement être renvoyés ?","a":["Avant le 10 du mois","Avant le 15 du mois","Avant le 20 du mois","Avant le 25 du mois"],"r":2,"e":"Les articles d\'un retour vendable doivent être renvoyés avant le 20 du mois. Cette date limite est précisée sur le listing envoyé le premier lundi du mois. Au-delà, le retour ne peut plus être pris en charge.|||💡 Retour vendable : deadline = avant le 20 du mois. Vérifier la date sur le listing reçu.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Lors d\'un retour vendable, quelles sont les deux actions obligatoires à effectuer sur les articles avant envoi ?","a":["Enlever les étiquettes prix et scanner les codes-barres","Enlever les étiquettes de responsabilité et cocher \'retour-vendable\' sur l\'étiquette de retour","Enlever les étiquettes prix et cocher \'retour non-vendable\'","Scanner les CNK dans Corilus et apposer une étiquette verte"],"r":1,"e":"Pour un retour vendable, deux actions sont obligatoires : enlever les étiquettes de responsabilité sur les articles, et cocher la case \'retour-vendable\' sur l\'étiquette de retour. Ces deux étapes sont essentielles pour que le retour soit accepté au dépôt.|||💡 Retour vendable : enlever étiquettes de responsabilité + cocher \'retour-vendable\' sur l\'étiquette. Les deux obligatoires.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Une officine reçoit le listing des retours vendables mais ne souhaite pas traiter certains articles. Que doit-elle faire ?","a":["Elle doit obligatoirement traiter tous les articles du listing","Elle peut ignorer le listing : il n\'y a pas d\'obligation de traitement","Elle doit justifier par écrit les articles non traités","Elle doit contacter la cellule fichiers pour signaler les articles refusés"],"r":1,"e":"L\'officine n\'a pas d\'obligation de traiter le listing de retours vendables si elle ne le souhaite pas. Le traitement est facultatif. Seuls les retraits produits sont obligatoires et soumis à un délai de 48h.|||💡 Retour vendable = aucune obligation de traitement. L\'officine choisit librement.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Quels types d\'articles font l\'objet d\'un retour non-vendable chez Familia ?","a":["Les articles en surstock avec potentiel de vente","Les articles périmés ou abîmés","Les articles rapatriés en fin d\'action marketing","Les articles transférés entre pharmacies"],"r":1,"e":"Les retours non-vendables concernent les articles périmés ou abîmés. Ils sont à distinguer des retours vendables (surstock avec potentiel), des rappels produits (fin d\'action marketing) et des transferts (entre officines). Cette catégorie peut être traitée à tout moment.|||💡 Non-vendable = périmé ou abîmé. Peut être traité à tout moment, sans calendrier imposé.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"À quel délai maximum avant péremption faut-il sortir les articles périmés pour un retour non-vendable ?","a":["1 mois maximum","2 mois maximum","3 mois maximum","6 mois maximum"],"r":2,"e":"La procédure Familia préconise de sortir les périmés à 3 mois maximum avant leur date de péremption. Il faut également être vigilant aux conditionnements adaptés à des durées de traitement longues (exemple : 13 plaquettes mais seulement 10 mois de péremption restants).|||💡 Sortir les périmés à 3 mois maximum. Attention aux gros conditionnements avec peu de péremption restante.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Combien de temps après le début d\'une action marketing le listing \'Rappel de produit\' est-il envoyé aux officines ?","a":["1 mois après le début de l\'action","2 mois après le début de l\'action","3 mois après le début de l\'action","À la fin de l\'action marketing"],"r":1,"e":"Le listing \'Rappel de produit\' est envoyé aux officines 2 mois après le début d\'une action marketing. Ce rappel concerne uniquement les articles envoyés via les Min-Max ou les Push. Les quantités rappelées sont définies par le service marketing.|||💡 Rappel produit = listing envoyé 2 mois après le début de l\'action marketing. Quantités définies par le marketing.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Lors d\'un rappel produit avec plusieurs cartons, que doit impérativement figurer sur chaque carton ?","a":["Le CNK et la dénomination de chaque article","Le numéro du rappel ET la première page du listing dans chaque carton","Le nom de la pharmacie expéditrice et la date d\'envoi","Le code EPC-Retours et le bon de livraison original"],"r":1,"e":"En cas de rappel produit avec plusieurs cartons, il est obligatoire d\'indiquer le numéro du rappel sur chaque carton ET d\'inclure la première page du listing dans chaque carton. Cette règle s\'applique aussi bien aux rappels automatiques qu\'aux rappels à la demande de la pharmacie.|||💡 Plusieurs cartons = numéro du rappel sur chaque carton + première page du listing dans chaque carton.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Quelles conditions doivent remplir les articles pour faire l\'objet d\'un rappel produit à la demande de la pharmacie ?","a":["Être périmés ou abîmés, gérés au dépôt","Être en surstock, gérés au dépôt, non retirés de vente, non pouce levés, hors action marketing","Être en surstock peu importe leur statut dans le système","Être des articles OTC uniquement avec potentiel dans d\'autres officines"],"r":1,"e":"Pour un rappel à la demande de la pharmacie, les articles doivent être en surstock ET répondre à 4 conditions cumulatives : gérés et stockés au dépôt, non retirés de vente, non \'pouce levés\', et hors action marketing en cours.|||💡 Rappel à la demande : surstock + géré au dépôt + non retiré de vente + non pouce levé + hors action marketing.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Dans quel délai une officine Familia doit-elle obligatoirement traiter un retrait produit après réception du listing ?","a":["24 heures","48 heures","72 heures","1 semaine"],"r":1,"e":"Les retraits produits doivent être traités dans les 48 heures suivant la réception du listing. C\'est une obligation. Le listing est envoyé par mail le jour de l\'encodage (J) et également dans les bacs le lendemain (J+1).|||💡 Retrait produit = obligation de traitement dans les 48h. Seul type de retour obligatoire.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Une officine reçoit un listing de retrait produit mais son stock de l\'article concerné est à 0. Que doit-elle faire ?","a":["Ne rien faire : pas de stock = pas de retour à effectuer","Renvoyer quand même le document avec la quantité indiquée à 0","Contacter la cellule fichiers pour signaler l\'absence de stock","Encoder 0 dans Corilus sans renvoyer de document physique"],"r":1,"e":"Même si la quantité en stock est de 0, l\'officine doit renvoyer le document listing avec la quantité de 0 indiquée. Le retrait produit est une obligation pour toutes les officines concernées, y compris celles sans stock.|||💡 Retrait produit avec stock 0 = renvoyer quand même le document avec quantité 0. Toujours obligatoire.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Comment les officines reçoivent-elles les listings de retrait produit ?","a":["Uniquement par mail","Uniquement dans les bacs","Par mail le jour J ET dans les bacs le lendemain J+1","Par mail uniquement si l\'officine possède l\'article en stock"],"r":2,"e":"Les listings de retrait produit sont communiqués de deux façons : par mail le jour de l\'encodage (J), et dans les bacs physiques le lendemain (J+1). Cette double communication garantit que l\'information parvient à l\'officine même en cas de problème de messagerie.|||💡 Retrait produit : mail le jour J + bacs le lendemain J+1. Double communication systématique.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Lors de la réception, le nombre de bacs n\'est pas correct. Quel est le premier réflexe à avoir ?","a":["Encoder les articles manquants comme non-livrables dans Corilus","Contacter le magasin au 2340 ou par mail magasin@pharmacie-familia.be","Ouvrir tous les bacs présents pour vérifier le contenu","Attendre la livraison suivante pour régularisation"],"r":1,"e":"En cas de nombre de bacs incorrect à la réception, il faut contacter le magasin immédiatement (2340 ou magasin@pharmacie-familia.be). Il faut aussi vérifier la présence de médicaments frigo pour les mettre en sécurité dans le réfrigérateur de la pharmacie en attendant.|||💡 Bac manquant ou en trop : appeler le 2340 ou magasin@pharmacie-familia.be. Vérifier d\'abord s\'il y a des frigos.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Lors de la réception, vous trouvez un article en trop dans un bac que vous souhaitez garder. Quelle est la procédure correcte ?","a":["Le noter dans Corilus comme réception non planifiée","Le renseigner sur le document REM et le scanner à REM","Le mettre dans le sac rouge avec le document \'Erreur de préparation Sac Rouge\'","L\'encoder dans EPC-Retours comme retour vendable"],"r":1,"e":"Un article en trop que l\'on souhaite garder doit être renseigné sur le document REM puis scanné à REM. Si on ne souhaite pas le garder, il doit être placé dans le sac rouge accompagné du document \'Erreur de préparation Sac Rouge\'.|||💡 Article en trop à garder = document REM + scan à REM. Article en trop à renvoyer = sac rouge + document dédié.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Lors de la réception, un article présent sur la note d\'envoi est absent du bac. Quelle est la procédure pour les articles manquants ?","a":["Encoder immédiatement une nouvelle commande pour compenser","Mettre l\'article en non-livrable dans Corilus et l\'identifier sur la note d\'envoi scannée à REM","Contacter le 2340 et attendre confirmation avant toute action","Faire un retour non-vendable de 0 unité dans EPC-Retours"],"r":1,"e":"Pour les articles manquants, la procédure est de les mettre en non-livrables dans Corilus, puis de les identifier sur la note d\'envoi que l\'on scanne ensuite à REM. Cette double action permet la traçabilité et la régularisation.|||💡 Article manquant = non-livrable dans Corilus + identification sur note d\'envoi scannée à REM.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Avant d\'envoyer un article en transfert vers une autre officine Familia, quelle condition est impérative ?","a":["Obtenir l\'accord de la cellule fichiers","Avoir l\'accord préalable de l\'officine destinatrice avant l\'envoi","Vérifier que l\'article n\'est pas en action marketing","Obtenir l\'accord de David Bei ou Sarah Piron"],"r":1,"e":"Avant tout transfert vers une autre officine, il est impératif d\'avoir l\'accord préalable de l\'officine destinatrice. On ne peut pas envoyer un article à une autre pharmacie sans son consentement, même si Galien indique qu\'elle a du potentiel de vente.|||💡 Transfert : accord de l\'officine destinatrice OBLIGATOIRE avant tout envoi. Ne jamais envoyer sans accord.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Dans quel contenant doit être placé un article pour un transfert standard (hors frigo) vers une autre officine ?","a":["Dans le bac bleu habituel","Dans le sac vert destiné au transfert","Dans le sac rouge avec la feuille de transfert","Dans un carton séparé avec étiquette EPC-Retours"],"r":1,"e":"Les articles en transfert standard doivent être emballés avec leur feuille de transfert (issue de Corilus), agrafée au sachet avec l\'officine destinatrice visible, puis placés dans le sac vert destiné au transfert. Le sac vert revient au dépôt via les bacs bleus.|||💡 Transfert standard = sac vert. Feuille de transfert agrafée, officine destinatrice visible. Délai : 2 jours ouvrables.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Lors d\'un transfert via Corilus, quel destinataire doit être renseigné dans le système ?","a":["EPC-Retours","L\'identifiant de la pharmacie destinatrice (Offxxx)","Le code postal de la pharmacie destinatrice","Le nom du pharmacien titulaire de la pharmacie destinatrice"],"r":1,"e":"Dans Corilus, le transfert doit être enregistré avec l\'identifiant de la pharmacie destinatrice (Offxxx), et non EPC-Retours. Cette erreur est fréquente et peut entraîner une mauvaise orientation des articles au dépôt. La même règle s\'applique pour les transferts frigo.|||💡 Transfert dans Corilus : renseigner Offxxx (pharmacie destinatrice), JAMAIS EPC-Retours.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Quel est le délai de réception pour un article transféré entre deux pharmacies Familia ?","a":["Le jour même","1 jour ouvrable","2 jours ouvrables","3 jours ouvrables"],"r":2,"e":"Le délai entre l\'envoi d\'une pharmacie et la réception par l\'officine destinatrice est de 2 jours ouvrables. Ce délai s\'applique aussi bien aux transferts standards qu\'aux transferts frigo.|||💡 Transfert entre officines : délai = 2 jours ouvrables. Valable pour transferts standards et frigo.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Avant d\'effectuer un transfert frigo entre deux officines, quelle démarche supplémentaire est requise par rapport à un transfert standard ?","a":["Contacter la cellule fichiers pour validation","Demander l\'accord de David Bei ou de Sarah Piron","Contacter l\'AFMPS pour déclaration préalable","Obtenir l\'accord des deux titulaires concernés"],"r":1,"e":"Pour un transfert frigo, en plus de l\'accord de l\'officine destinatrice, il faut demander l\'accord de David Bei ou de Sarah Piron avant d\'initier le transfert dans Corilus. Cette étape supplémentaire n\'existe pas pour les transferts standards.|||💡 Transfert frigo = accord David Bei ou Sarah Piron obligatoire, en plus de l\'accord de l\'officine destinatrice.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Comment doivent être conditionnés les articles frigo pour un transfert ou retour frigo ?","a":["Dans le bac bleu avec une pochette isotherme","Dans une sacoche frigo avec des glaçons bien froids, placé dans le bac frigo en fin de journée","Dans le sac vert habituel avec mention \'fragile\'","Dans un carton isolant fermé avec un thermomètre"],"r":1,"e":"Les articles frigos doivent être placés dans une sacoche frigo avec des glaçons bien froids (glaçons mis au congélateur pendant toute la journée). La sacoche est placée dans le bac frigo en fin de journée. L\'identification claire du transfert frigo est obligatoire pour le chauffeur.|||💡 Transfert/retour frigo : sacoche frigo + glaçons congelés toute la journée + bac frigo en fin de journée.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Quelles informations fournir à David Bei ou Sarah Piron pour un retour frigo suite à une erreur de commande ?","a":["Uniquement le CNK et la quantité","Date de commande/livraison, CNK, dénomination, quantité et date de péremption","Nom du fournisseur, numéro de lot, CNK et quantité","CNK, quantité et prix d\'achat unitaire"],"r":1,"e":"Pour un retour frigo suite à une erreur de commande ou de livraison, il faut fournir : la date de la commande/livraison, le CNK, la dénomination, la quantité et la date de péremption. La date de commande/livraison n\'est requise qu\'en cas d\'erreur de commande ou de livraison.|||💡 Retour frigo erreur : date livraison + CNK + dénomination + quantité + date péremption. Tout est nécessaire.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Une officine constate une erreur de livraison sur un stupéfiant. Quel est le premier réflexe à avoir ?","a":["Faire un retour non-vendable directement dans EPC-Retours","Contacter directement le 2220 pour coordination avec Narcoreg","Envoyer un mail à m.gillet@pharmacie-familia.be","Appliquer la procédure retour vendable standard"],"r":1,"e":"En cas d\'erreur de livraison sur un stupéfiant, il faut contacter directement le 2220. Ce contact permet de se coordonner sur les actions à effectuer par rapport à Narcoreg, qui nécessite une gestion spécifique pour tout mouvement de stupéfiant.|||💡 Erreur livraison stupéfiant = appeler le 2220 immédiatement pour coordination Narcoreg.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Une officine souhaite renvoyer des stupéfiants périmés au dépôt. Quelle démarche préalable est obligatoire ?","a":["Encoder le retour dans EPC-Retours sans démarche préalable","Envoyer un mail à m.gillet@pharmacie-familia.be avant d\'envoyer les stupéfiants","Contacter le 2220 et attendre la validation AFMPS","Faire une déclaration Narcoreg avant le retour"],"r":1,"e":"Avant de renvoyer des stupéfiants périmés, il est obligatoire d\'envoyer un mail à m.gillet@pharmacie-familia.be pour prévenir qu\'on va renvoyer ces produits. Le dépôt les centralisera et les détruira. Ces retours ne sont pas une transaction à renseigner sur Narcoreg.|||💡 Stupéfiants périmés à renvoyer : prévenir m.gillet@pharmacie-familia.be AVANT l\'envoi. Pas de déclaration Narcoreg.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Intermédiaire","q":"Comment doivent être conditionnés les stupéfiants périmés lors de leur retour au dépôt ?","a":["Mélangés avec les autres articles non-vendables dans le même carton","Dans un carton séparé, uniquement pour les stupéfiants","Dans le sac rouge avec le document erreur de préparation","Dans le sac jaune des médicaments ramenés par les patients"],"r":1,"e":"Les stupéfiants périmés doivent impérativement être renvoyés dans un carton séparé, uniquement dédié aux stupéfiants. Ils ne doivent jamais être mélangés avec d\'autres articles non-vendables. Ces produits ne réintègrent pas le stock du dépôt : ils sont centralisés et détruits.|||💡 Stupéfiants périmés = carton SÉPARÉ, jamais mélangé aux autres retours.","type_question":"qcm"},
  {"t":"Procedure","sub":"retours","d":"Basique","q":"Un patient rapporte des médicaments contenant des stupéfiants à l\'officine. Comment doit-on les traiter ?","a":["Les renvoyer au dépôt dans un carton séparé après contact avec m.gillet","Les mettre dans le sachet jaune des médicaments périmés, traités comme les autres médicaments ramenés par le patient","Les conserver dans l\'armoire à stupéfiants de la pharmacie","Les déclarer sur Narcoreg avant de les éliminer"],"r":1,"e":"Les stupéfiants ramenés par les patients sont traités comme les autres médicaments ramenés par les patients : placés dans le sachet jaune des médicaments périmés. Cette procédure est distincte du retour des stupéfiants périmés du stock de la pharmacie.|||💡 Stupéfiants ramenés par le patient = sachet jaune médicaments périmés. Identique aux autres médicaments.","type_question":"qcm"}
];
