const RELIER_FLUX_QDB = [{"type_question":"relier","theme":"Procédure","sub":"retours","niveau":"Basique","consigne":"Associez chaque type de retour Familia à la case correcte sur l'étiquette de retour.","gauche":["Retour vendable","Retour non-vendable","Rappel produit","Retrait produit"],"droite":["Retrait produit","Retour non-vendable","Rappel produit","Retour-vendable"],"correspondances":{"1":"Retour-vendable","2":"Retour non-vendable","3":"Rappel produit","4":"Retrait produit"},"explication":"Chaque type de retour Familia possède sa propre case sur l'étiquette de retour. Cocher la mauvaise case entraîne un mauvais traitement au dépôt. Retour vendable → 'retour-vendable', périmés/abîmés → 'retour non-vendable', fin d'action marketing → 'rappel produit', recall APB/firme → 'retrait produit'.","point_pratique":"💡 Toujours vérifier la case cochée sur l'étiquette avant d'envoyer : chaque type de retour a sa case dédiée.","d":"Basique"},{"type_question":"relier","theme":"Médicaments","sub":"cbip","niveau":"Intermédiaire","consigne":"Associez chaque médicament à son risque principal en cas d'association avec un AINS.","gauche":["Warfarine","Méthotrexate","Lithium","IEC + diurétique"],"droite":["Risque rénal aigu (triple whammy)","Toxicité lithium augmentée","Risque hémorragique majeur","Toxicité hématologique augmentée"],"correspondances":{"1":"Risque hémorragique majeur","2":"Toxicité hématologique augmentée","3":"Toxicité lithium augmentée","4":"Risque rénal aigu (triple whammy)"},"explication":"Les AINS interagissent de façon dangereuse avec plusieurs traitements : avec la warfarine (potentialisation anticoagulante → hémorragie), avec le méthotrexate (compétition rénale → toxicité hématologique), avec le lithium (réduction excrétion rénale → toxicité), et avec IEC+diurétique (triple réduction perfusion rénale → insuffisance rénale aiguë).","point_pratique":"💡 Avant tout AINS en OTC : vérifier systématiquement warfarine, méthotrexate, lithium, IEC+diurétique dans le dossier pharmaceutique.","d":"Intermédiaire"},{"type_question":"relier","theme":"Déontologie","sub":"deon_ethique","niveau":"Intermédiaire","consigne":"Associez chaque situation déontologique à sa qualification correcte.","gauche":["Pharmacien accepte une prime conditionnée à la recommandation d'un produit","Pharmacien critique publiquement un confrère sur les réseaux","Pharmacien divulgue le traitement d'un patient à son employeur","Pharmacien adjoint signe des actes non accomplis"],"droite":["Violation du secret professionnel","Fausse certification","Collusion interdite","Dénigrement de confrère"],"correspondances":{"1":"Collusion interdite","2":"Dénigrement de confrère","3":"Violation du secret professionnel","4":"Fausse certification"},"explication":"Ces quatre situations représentent des manquements déontologiques distincts : accepter une prime conditionnée = collusion (indépendance compromise), critiquer un confrère publiquement = dénigrement, divulguer un traitement = violation du secret professionnel, signer des actes non accomplis = fausse certification engageant la responsabilité pénale.","point_pratique":"💡 Chaque manquement déontologique a une qualification précise. Les connaître aide à les identifier et les éviter au quotidien.","d":"Intermédiaire"},{"type_question":"relier","theme":"Préparations magistrales","sub":"ftm_etiquetage","niveau":"Basique","consigne":"Associez chaque mention obligatoire de l'étiquette d'une préparation magistrale à son objectif.","gauche":["Date de péremption","Numéro de lot des matières premières","Nom du patient","Voie d'administration"],"droite":["Traçabilité en cas de rappel matière première","Caractère nominatif de la préparation","Sécurité d'utilisation et prévention des erreurs","Limite de sécurité d'utilisation"],"correspondances":{"1":"Limite de sécurité d'utilisation","2":"Traçabilité en cas de rappel matière première","3":"Caractère nominatif de la préparation","4":"Sécurité d'utilisation et prévention des erreurs"},"explication":"Chaque mention obligatoire sur l'étiquette d'une préparation magistrale répond à un objectif précis de sécurité : la date de péremption fixe la limite de sécurité, le numéro de lot assure la traçabilité en cas de rappel, le nom du patient rappelle le caractère nominatif, et la voie d'administration prévient les erreurs d'utilisation.","point_pratique":"💡 Étiquette préparation magistrale : chaque mention manquante est une non-conformité. Vérifier systématiquement avant remise.","d":"Basique"},{"type_question":"relier","theme":"Conseil officinal","sub":"derma","niveau":"Basique","consigne":"Associez chaque symptôme cutané à l'orientation conseil correcte.","gauche":["Démangeaisons nocturnes diffuses + boutons dans l'entourage","Plaques rouges derrière les oreilles + troubles du sommeil nourrisson","Rougeurs permanentes sur les joues avec petits vaisseaux visibles","Talons fissurés et calleux profonds"],"droite":["Urea 30% + application sous chaussettes le soir","Orienter vers le pédiatre : tableau évocateur de dermatite atopique","Toleriane Rosaliac AR + protection solaire","Orienter vers le médecin : tableau évocateur de gale"],"correspondances":{"1":"Orienter vers le médecin : tableau évocateur de gale","2":"Orienter vers le pédiatre : tableau évocateur de dermatite atopique","3":"Toleriane Rosaliac AR + protection solaire","4":"Urea 30% + application sous chaussettes le soir"},"explication":"Chaque tableau clinique oriente vers une prise en charge différente : démangeaisons nocturnes + entourage atteint = gale (médecin), plaques + sommeil perturbé nourrisson = dermatite atopique (pédiatre), rougeurs vasculaires joues = rosacée (Rosaliac AR), talons calleux = Urea 30% kératolytique.","point_pratique":"💡 Tableau clinique = orientation avant tout produit. Ne jamais conseiller sans évaluer d'abord.","d":"Basique"},{"type_question":"relier","theme":"BPP Officinales","sub":"bppo_qualite","niveau":"Intermédiaire","consigne":"Associez chaque type d'erreur de réception à la procédure correcte chez Familia.","gauche":["Nombre de bacs incorrect à la réception","Article en trop dans un bac, que l'on souhaite garder","Article manquant sur la note d'envoi","Article abîmé dans un bac"],"droite":["Retour non-vendable + joindre la note d'envoi","Non-livrable dans Corilus + note d'envoi scannée à REM","Document REM + scanner à REM","Contacter le 2340 ou magasin@pharmacie-familia.be"],"correspondances":{"1":"Contacter le 2340 ou magasin@pharmacie-familia.be","2":"Document REM + scanner à REM","3":"Non-livrable dans Corilus + note d'envoi scannée à REM","4":"Retour non-vendable + joindre la note d'envoi"},"explication":"Chaque type d'erreur de réception a sa procédure spécifique : bac manquant/en trop = appeler le 2340, article en trop à garder = document REM + scan REM, article manquant = non-livrable Corilus + note d'envoi à REM, article abîmé = retour non-vendable avec note d'envoi jointe.","point_pratique":"💡 Réception : distinguer les 4 types d'erreurs possibles. Chacune a sa procédure. Ne pas mélanger les actions.","d":"Intermédiaire"},{"type_question":"relier","theme":"Procédure","sub":"stupefiants","niveau":"Intermédiaire","consigne":"Associez chaque situation liée aux stupéfiants à la personne ou instance à contacter en priorité.","gauche":["Erreur de livraison d'un stupéfiant","Retour de stupéfiants périmés au dépôt","Transfert frigo d'un stupéfiant vers une autre officine","Accès Narcoreg bloqué en l'absence du titulaire"],"droite":["David Bei ou Sarah Piron","d.bei@pharmacie-familia.be (coresponsable Narcoreg)","m.gillet@pharmacie-familia.be","Le 2220"],"correspondances":{"1":"Le 2220","2":"m.gillet@pharmacie-familia.be","3":"David Bei ou Sarah Piron","4":"d.bei@pharmacie-familia.be (coresponsable Narcoreg)"},"explication":"Chaque situation stupéfiants a son interlocuteur dédié : erreur de livraison → 2220 (coordination Narcoreg), retour périmés → m.gillet@pharmacie-familia.be (prévenir avant envoi), transfert frigo → David Bei ou Sarah Piron (accord préalable obligatoire), Narcoreg bloqué → d.bei@pharmacie-familia.be (coresponsable cogestion).","point_pratique":"💡 Stupéfiants : avoir les bons contacts à portée. Le mauvais interlocuteur = délai et non-conformité.","d":"Intermédiaire"},{"type_question":"relier","theme":"Dermo-cosmétique","sub":"lrp","niveau":"Intermédiaire","consigne":"Associez chaque médicament ou traitement à la précaution cosmétique principale.","gauche":["Isotrétinoïne orale","Méthotrexate","Rétinoïdes oraux (femme en âge de procréer)","Patient sous chimiothérapie"],"droite":["Produits portant le logo Cancer Support uniquement","Contraception efficace documentée obligatoire","Éviter tout cosmétique contenant vitamine A (rétinol)","Protection solaire maximale et systématique"],"correspondances":{"1":"Éviter tout cosmétique contenant vitamine A (rétinol)","2":"Protection solaire maximale et systématique","3":"Contraception efficace documentée obligatoire","4":"Produits portant le logo Cancer Support uniquement"},"explication":"Chaque traitement impose une vigilance cosmétique spécifique : isotrétinoïne + rétinol topique = potentialisation irritante (contre-indiqué), méthotrexate = photosensibilisant (SPF maximal et systématique), rétinoïdes oraux = tératogènes (contraception obligatoire), chimiothérapie = privilégier les produits testés Cancer Support.","point_pratique":"💡 Traitement systémique = toujours évaluer l'impact sur les conseils cosmétiques avant de recommander quoi que ce soit.","d":"Intermédiaire"},{"type_question":"flux","theme":"Procédure","sub":"stupefiants","niveau":"Intermédiaire","consigne":"Complétez l'étape manquante dans la procédure de délivrance d'un traitement de substitution (TSO) à un nouveau patient.","flux":["Réception d'une ordonnance TSO pour un patient inconnu de la pharmacie","Vérification de la validité et de l'authenticité de l'ordonnance","[ ? ]","Délivrance selon les modalités prescrites + enregistrement Narcoreg"],"propositions":{"A":"Demander une pièce d'identité au patient","B":"Vérifier l'absence de double suivi dans une autre pharmacie","C":"Contacter l'AFMPS pour déclaration préalable","D":"Appeler le médecin pour confirmer la prescription"},"bonne_reponse":"B","explication":"Avant toute première délivrance d'un TSO à un patient inconnu, le pharmacien doit vérifier qu'il n'est pas déjà suivi dans une autre pharmacie. Cette vérification via le dossier pharmaceutique partagé prévient le double suivi non coordonné. L'appel au médecin n'est pas systématiquement requis si l'ordonnance est valide et le double suivi exclu.","point_pratique":"💡 TSO nouveau patient : vérifier l'absence de double suivi AVANT toute première délivrance. Étape non négociable.","d":"Intermédiaire"},{"type_question":"flux","theme":"Préparations magistrales","sub":"ftm_etiquetage","niveau":"Expert","consigne":"Complétez l'étape manquante dans la procédure de réalisation d'une préparation magistrale pédiatrique.","flux":["Réception de la prescription magistrale pédiatrique","Consultation de la FTM ou du CTPP pour la monographie","[ ? ]","Réalisation de la préparation avec contrôle de pesée"],"propositions":{"A":"Commander les matières premières manquantes","B":"Calculer la posologie selon le poids et faire vérifier par un second pharmacien","C":"Vérifier la date de péremption des matières premières","D":"Informer le prescripteur du délai de préparation"},"bonne_reponse":"B","explication":"Entre la consultation de la FTM et la réalisation de la préparation, le calcul de posologie pédiatrique selon le poids doit impérativement être vérifié par un second pharmacien (principe des 4 yeux). Chez l'enfant, les marges thérapeutiques sont étroites et une erreur de calcul peut être fatale. Cette vérification précède la pesée.","point_pratique":"💡 Préparation pédiatrique : calcul posologie = toujours double vérification. Principe des 4 yeux avant toute pesée.","d":"Expert"},{"type_question":"flux","theme":"Conseil officinal","sub":"gyneco","niveau":"Intermédiaire","consigne":"Complétez l'étape manquante dans le raisonnement pharmacien face à une demande d'AINS chez une femme enceinte.","flux":["Patiente enceinte demande un antalgique pour maux de tête","Identification du stade de la grossesse (trimestre)","[ ? ]","Conseil paracétamol + recommandation de consulter si persistance"],"propositions":{"A":"Proposer l'ibuprofène à demi-dose au T1 si douleur intense","B":"Vérifier si elle a une ordonnance pour l'AINS demandé","C":"Déconseiller formellement tout AINS dès le T1 et expliquer le risque fœtal","D":"Orienter vers le médecin sans donner de conseil"},"bonne_reponse":"C","explication":"Face à une demande d'AINS chez une femme enceinte, après avoir identifié le trimestre, l'étape clé est de déconseiller formellement les AINS dès le T1 et d'expliquer le risque fœtal (fermeture prématurée du canal artériel au T2-T3, toxicité rénale). Proposer le paracétamol comme alternative est l'étape suivante. Donner l'ibuprofène même à demi-dose n'est jamais justifié.","point_pratique":"💡 AINS en grossesse : déconseiller dès le T1, expliquer pourquoi, proposer paracétamol. Dans cet ordre.","d":"Intermédiaire"},{"type_question":"flux","theme":"Procédure","sub":"retours","niveau":"Basique","consigne":"Complétez l'étape manquante dans la procédure de retrait produit Familia.","flux":["Réception du listing de retrait produit (par mail J et bacs J+1)","Identification des articles concernés dans le stock","[ ? ]","Envoi du carton avec le listing joint dans les 48h"],"propositions":{"A":"Contacter le fournisseur pour confirmation","B":"Encoder le retrait dans Corilus via EPC-Retours et cocher 'Retrait produit'","C":"Attendre validation de la cellule fichiers avant d'agir","D":"Mettre les articles dans le sac rouge en attendant"},"bonne_reponse":"B","explication":"Après avoir identifié les articles, l'étape obligatoire est d'encoder le retrait dans Corilus via le menu EPC-Retours en cochant la case 'Retrait produit'. Cette encodage déclenche la traçabilité administrative. Si le stock est à 0, l'encodage est quand même réalisé et le document renvoyé avec quantité 0.","point_pratique":"💡 Retrait produit : encoder dans Corilus (EPC-Retours / Retrait produit) AVANT de préparer le carton. Dans les 48h obligatoires.","d":"Basique"},{"type_question":"flux","theme":"Déontologie","sub":"deon_ethique","niveau":"Intermédiaire","consigne":"Complétez l'étape manquante dans la gestion d'un conflit déontologique persistant entre un pharmacien adjoint et son titulaire.","flux":["Pharmacien adjoint identifie une pratique contraire au code de déontologie","Refus de l'adjoint de participer à cette pratique","[ ? ]","Saisine du Conseil provincial de l'Ordre si le conflit persiste"],"propositions":{"A":"Démissionner immédiatement pour éviter toute complicité","B":"Maintenir le refus et documenter les faits par écrit","C":"Accepter provisoirement en attendant de changer d'employeur","D":"Contacter l'AFMPS pour signalement anonyme"},"bonne_reponse":"B","explication":"Entre le refus initial et la saisine de l'Ordre, l'étape intermédiaire est de maintenir fermement le refus et de documenter les faits par écrit. Cette documentation constitue une preuve en cas de procédure disciplinaire ultérieure. La démission immédiate n'est pas requise, et accepter provisoirement engagerait la responsabilité de l'adjoint.","point_pratique":"💡 Conflit déontologique : refuser + documenter par écrit + Ordre si persistance. Trois étapes dans l'ordre.","d":"Intermédiaire"},{"type_question":"flux","theme":"BPP Officinales","sub":"bppo_qualite","niveau":"Intermédiaire","consigne":"Complétez l'étape manquante dans la gestion d'un médicament réfrigéré retrouvé à température ambiante depuis plus d'1 heure.","flux":["Détection d'un médicament réfrigéré sur le comptoir depuis plus d'1 heure","[ ? ]","Contact avec le fournisseur ou consultant les données de stabilité","Décision de délivrer ou de ne pas délivrer selon les données obtenues"],"propositions":{"A":"Remettre immédiatement le médicament au réfrigérateur","B":"Mettre le médicament en quarantaine et ne pas le délivrer en attendant","C":"Délivrer le médicament car la durée est inférieure à 4 heures","D":"Faire un retour non-vendable immédiatement sans contacter le fournisseur"},"bonne_reponse":"B","explication":"Face à un médicament réfrigéré sorti du froid depuis plus d'1 heure, la première action est de le mettre en quarantaine (ne pas le délivrer) en attendant de consulter les données de stabilité auprès du fournisseur. Remettre au frigo sans démarche ne garantit pas la qualité. Délivrer sans vérification engage la responsabilité du pharmacien.","point_pratique":"💡 Médicament frigo sorti > 1h : quarantaine immédiate, ne pas délivrer, contacter le fournisseur. Pas de décision unilatérale.","d":"Intermédiaire"}];
